let activeLanguage = 'tr';
let activePage = 'home';
let portalMemberSession = false;
let portalAdminSession = false;

const pageRoutes = {
  home: [
    'top',
    'hakkinda',
    'basinda',
    'yasam-rehberi',
    'topics',
    'sertifikalar',
    'alanlar',
    'deneyimlerim',
    'dijital-merkez',
    'platforms',
  ],
  feedback: ['ameliyat-olanlardan-gelenler'],
  hakkinda: ['doctor-profile'],
  jinekologum: ['jinekologum', 'jinekologum-sorularim', 'jinekologum-dokumanlarim', 'jinekologum-dokuman-okuyucu', 'jinekologum-doktorum'],
  sertifikalar: ['sertifikalar'],
  alanlar: ['alanlar', 'topics'],
  'genital-performans': ['sayfa-genital-performans', 'genital-performans'],
  hpv: ['sayfa-hpv', 'hpv'],
  'kanser-ansiklopedisi': ['sayfa-kanser-ansiklopedisi', 'kanser-ansiklopedisi'],
  'saglikli-hamilelik': ['sayfa-saglikli-hamilelik', 'saglikli-hamilelik'],
  'yasam-rehberi': ['yasam-rehberi'],
  videolar: ['basinda', 'platforms'],
  bilgilendirme: ['bilgilendirme', 'gorsel-dil'],
  deneyimlerim: ['deneyimlerim'],
  platforms: ['basinda', 'platforms'],
  iletisim: ['dijital-merkez'],
};

const idToRoute = Object.entries(pageRoutes).reduce((acc, [route, ids]) => {
  ids.forEach((id) => {
    acc[id] = route;
  });
  acc['saglikli-kadin-icerigi'] = 'yasam-rehberi';
  return acc;
}, {});

function getRouteFromHash(hash = window.location.hash) {
  const id = decodeURIComponent(String(hash || '').replace(/^#/, '')) || 'home';
  if (id.startsWith('hpv-article-')) return 'hpv';
  return idToRoute[id] || (pageRoutes[id] ? id : 'home');
}

function normalizeInternalLink(link) {
  const rawHash = link.getAttribute('href') || '';
  if (!rawHash.startsWith('#')) return;
  const id = rawHash.slice(1);
  const route = getRouteFromHash(rawHash);
  link.dataset.pageLink = route;
  if (id === 'home') link.setAttribute('href', '#top');
}

function setupPagePanels() {
  document.body.classList.add('is-page-mode');
}

function orderPrioritySections() {
  const healthyContent = document.getElementById('yasam-rehberi');
  const pressSection = document.getElementById('basinda');
  const topicsSection = document.getElementById('topics');
  if (pressSection && healthyContent) pressSection.after(healthyContent);
  if (healthyContent && topicsSection) healthyContent.after(topicsSection);
}

function setActiveRouteSections(route) {
  const activeIds = new Set(pageRoutes[route] || pageRoutes.home);
  document.querySelectorAll('main > section').forEach((section) => {
    section.classList.toggle('is-route-active', activeIds.has(section.id));
  });
}

function setActiveNav(route) {
  document.querySelectorAll('[data-page-link]').forEach((link) => {
    const isActive = link.dataset.pageLink === route;
    link.classList.toggle('is-active', isActive);
    if (isActive && link.closest('.nav-links')) {
      link.setAttribute('aria-current', 'page');
    } else if (link.closest('.nav-links')) {
      link.removeAttribute('aria-current');
    }
  });
}

function activatePage(route, options = {}) {
  const nextRoute = pageRoutes[route] ? route : 'home';
  activePage = nextRoute;
  setActiveRouteSections(nextRoute);
  setActiveNav(nextRoute);
  if (nextRoute === 'jinekologum') {
    const hash = String(window.location.hash || '');
    const panelName = hash.includes('dokuman-okuyucu') ? 'document-reader' : hash.includes('dokumanlarim') ? 'documents' : hash.includes('doktorum') ? 'doctor' : 'questions';
    activatePortalPanel(panelName);
  }
  if (nextRoute === 'hpv') {
    const match = String(window.location.hash || '').match(/^#hpv-article-(\d{2})$/);
    activeHpvArticleIndex = match ? Math.max(0, Number.parseInt(match[1], 10) - 1) : null;
    renderHpvKnowledge(activeLanguage);
  }
  updateLanguageLinks();
  const targetId = pageRoutes[nextRoute]?.[0] || 'top';
  const target = document.getElementById(targetId) || document.getElementById('top');
  if (options.updateHash !== false) {
    const url = new URL(window.location.href);
    url.hash = targetId;
    window.history.pushState({}, '', `${url.pathname}${url.search}${url.hash}`);
  }
  if (options.scroll !== false && target) {
    const scrollToTarget = () => target.scrollIntoView({ block: 'start', behavior: options.instant ? 'auto' : 'smooth' });
    if (options.instant) {
      scrollToTarget();
    } else {
      window.requestAnimationFrame(scrollToTarget);
    }
  }
}

function setupInternalRouting() {
  document.querySelectorAll('a[href^="#"]').forEach((link) => {
    normalizeInternalLink(link);
    link.addEventListener('click', (event) => {
      const rawHash = link.getAttribute('href') || '';
      const id = rawHash.slice(1) || 'top';
      const route = getRouteFromHash(`#${id}`);
      if (!route) return;
      event.preventDefault();
      activatePage(route);
      if (menu && menuButton) {
        menu.removeAttribute('data-open');
        menuButton.setAttribute('aria-expanded', 'false');
      }
    });
  });
  window.addEventListener('popstate', () => {
    activatePage(getRouteFromHash(), { updateHash: false, instant: true });
  });
  window.addEventListener('hashchange', () => {
    activatePage(getRouteFromHash(), { updateHash: false, instant: true });
  });
}

function setupTopicCards() {
  document.querySelectorAll('[data-topic-route]').forEach((card) => {
    const route = card.dataset.topicRoute;
    const openRoute = () => activatePage(route);
    card.addEventListener('click', openRoute);
    card.addEventListener('keydown', (event) => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        openRoute();
      }
    });
  });
}


