function buildLocalizedGuideBlog(language, item, title) {
  if (language === 'tr') return item.blog;
  const languageCopy = guideLocalizedCategoryCopy[language] || guideLocalizedCategoryCopy.en;
  const categoryCopy = languageCopy[item.categoryKey] || languageCopy['genital-performans'];
  const paragraphs = categoryCopy.blog(title, item);
  return {
    intro: paragraphs[0],
    development: paragraphs[1],
    conclusion: paragraphs[2],
  };
}

function getLocalizedGuideParent(language, item) {
  if (language === 'tr') {
    return {
      parentTitle: item.parentTitle,
      parentDescription: item.parentDescription,
    };
  }
  const parentCopy = guideLocalizedParentCopy[language]?.[item.parentSlug] || null;
  return {
    parentTitle: parentCopy?.title || item.localized?.[language]?.parentTitle || '',
    parentDescription: parentCopy?.description || item.localized?.[language]?.parentDescription || '',
  };
}

function getLocalizedGuideCards(language = activeLanguage) {
  if (language === 'tr') return approvedGuideCards;
  const labels = guideLanguageLabels[language] || guideLanguageLabels.en;
  const titles = guideLocalizedTitleMatrix[language] || guideLocalizedTitleMatrix.en;
  const languageCopy = guideLocalizedCategoryCopy[language] || guideLocalizedCategoryCopy.en;
  return approvedGuideCards.map((item, index) => {
    const localized = item.localized?.[language] || null;
    const title = localized?.title || titles[index] || item.title;
    const categoryCopy = languageCopy[item.categoryKey] || languageCopy['genital-performans'];
    const localizedBody = Array.isArray(localized?.body) && localized.body.length ? localized.body : null;
    const parent = getLocalizedGuideParent(language, item);
    const localizedBlog = localized?.blog || buildLocalizedGuideBlog(language, item, title);
    const description = item.categoryKey === 'saglikli-hamilelik'
      ? categoryCopy.description(title, item)
      : (localized?.description || categoryCopy.description(title, item));
    return {
      ...item,
      category: labels.categories[item.categoryKey] || item.category,
      title,
      description,
      body: localizedBody || [],
      parentTitle: parent.parentTitle,
      parentDescription: parent.parentDescription,
      readTime: labels.readTime,
      cta: labels.cta,
      ariaSuffix: labels.ariaSuffix,
      blog: localizedBody ? null : localizedBlog,
    };
  });
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function isDraftPlaceholderText(value = '') {
  const text = String(value || '').trim();
  if (!text) return true;
  return /sonraki içerik|içerik yüklemesinde|içerik dosyasında|açılacaktır|yakında eklenecek|coming soon|next content|next content file|will open with the next|will be available with the next|next content update|prochain fichier|prochaine mise à jour|sera disponible avec le prochain|prossimo file|prossimo aggiornamento|sarà disponibile con il prossimo|nächsten Inhaltsdatei|nächsten Inhaltsupdate|wird mit der nächsten|ملف المحتوى التالي|تحديث المحتوى التالي|سيُتاح|следующим файлом|следующим обновлением|будет открыт со следующим|подготавливается/i.test(text);
}

