function getHealthyContentUi(language = activeLanguage) {
  return translations[language]?.healthyContentUi || translations.tr.healthyContentUi;
}

function cleanLifeText(value) {
  return String(value || '')
    .replace(/\\'/g, "'")
    .replace(/\\"/g, '"')
    .replace(/<br\s*\/?>/gi, ' ')
    .replace(/<\/p>\s*<p>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;|&apos;/gi, "'")
    .replace(/&lt;|&gt;/gi, ' ')
    .replace(/---/g, '—')
    .replace(/\s+/g, ' ')
    .trim();
}

function isLifeInstructionText(value) {
  const text = String(value || '').toLocaleLowerCase('tr-TR');
  return /wix['’]?e?\s+nasıl|wix.*yerleş|görsel\s+tarif|visual\s+(brief|direction|description)|perplexity|dall|dall·e|dall-e|nasıl\s+yerleşecek|come\s+inserire|wie\s+platz|comment\s+intégrer|описание\s+визуала|визуал|وصف\s+بصري|تعليمات\s+بصرية/.test(text);
}

function stripLifeInstructionTables(markdown) {
  const withoutHtmlInstructionTables = String(markdown || '')
    .replace(/<table[\s\S]*?<\/table>/gi, (block) => (isLifeInstructionText(block) ? '\n' : block));
  const lines = withoutHtmlInstructionTables.split(/\r?\n/);
  const result = [];
  let inBox = false;
  let inPipeInstruction = false;
  lines.forEach((line) => {
    const trimmed = line.trim();
    if (/^\+[-+]+\+$/.test(trimmed)) {
      inBox = !inBox;
      return;
    }
    if (inBox) return;
    if (/^\|/.test(trimmed) && isLifeInstructionText(trimmed)) {
      inPipeInstruction = true;
      return;
    }
    if (inPipeInstruction) {
      if (/^\|/.test(trimmed) || /^[-|:\s]+$/.test(trimmed) || !trimmed) return;
      inPipeInstruction = false;
    }
    if (isLifeInstructionText(trimmed)) return;
    if (/^<\/?(table|tbody|thead|tr|td|th|colgroup|col)\b/i.test(trimmed)) return;
    result.push(line);
  });
  return result.join('\n');
}

function readWrappedMarkdownMark(lines, startIndex, mark) {
  let index = startIndex;
  let line = lines[index]?.trim() || '';
  if (!line.startsWith(mark)) return { text: '', nextIndex: startIndex };
  line = line.slice(mark.length);
  const collected = [];
  while (index < lines.length) {
    const isLast = line.trim().endsWith(mark);
    collected.push(isLast ? line.trim().slice(0, -mark.length) : line);
    index += 1;
    if (isLast) break;
    line = lines[index]?.trim() || '';
  }
  return { text: cleanLifeText(collected.join(' ')), nextIndex: index };
}

function readLifeMarkdownHeading(lines, startIndex) {
  const line = lines[startIndex]?.trim() || '';
  const match = line.match(/^#{1,4}\s+(.+)$/);
  if (!match) return { text: '', nextIndex: startIndex };
  return { text: cleanLifeText(match[1]), nextIndex: startIndex + 1 };
}

function readLifeQuote(lines, startIndex) {
  let index = startIndex;
  const collected = [];
  while (index < lines.length && lines[index].trim().startsWith('>')) {
    collected.push(lines[index].trim().replace(/^>\s?/, ''));
    index += 1;
  }
  const text = cleanLifeText(
    collected
      .join(' ')
      .replace(/^\*+/, '')
      .replace(/\*+$/, '')
      .replace(/\*\*\*/g, '')
      .replace(/\*\*/g, ''),
  );
  return { text, nextIndex: index };
}

function parseLifeArticleBlocks(lines, startIndex) {
  const blocks = [];
  let index = startIndex;
  while (index < lines.length) {
    const line = lines[index]?.trim() || '';
    if (!line) {
      index += 1;
      continue;
    }
    if (line.startsWith('>')) {
      const quote = readLifeQuote(lines, index);
      blocks.push({ type: /^Dr\. notu/i.test(quote.text) ? 'note' : 'quote', text: quote.text });
      index = quote.nextIndex;
      continue;
    }
    if (/^#{1,4}\s+/.test(line)) {
      const heading = readLifeMarkdownHeading(lines, index);
      blocks.push({ type: 'heading', text: heading.text });
      index = heading.nextIndex;
      continue;
    }
    if (line.startsWith('**')) {
      const heading = readWrappedMarkdownMark(lines, index, '**');
      blocks.push({ type: 'heading', text: heading.text });
      index = heading.nextIndex;
      continue;
    }
    const paragraph = [];
    while (index < lines.length) {
      const nextLine = lines[index]?.trim() || '';
      if (!nextLine) break;
      if (nextLine.startsWith('>') || nextLine.startsWith('**')) break;
      paragraph.push(nextLine);
      index += 1;
    }
    blocks.push({ type: 'paragraph', text: cleanLifeText(paragraph.join(' ')) });
  }
  return blocks.filter((block) => block.text && !isLifeInstructionText(block.text));
}

function parseLifeMarkdown(markdown, marker = 1) {
  const parts = stripLifeInstructionTables(markdown).split(new RegExp(`^\\*\\*${marker}\\.(\\d)\\*\\*\\s*$`, 'm'));
  const articles = [];
  for (let i = 1; i < parts.length; i += 2) {
    const number = Number.parseInt(parts[i], 10);
    const lines = parts[i + 1].split(/\r?\n/);
    let index = 0;
    while (index < lines.length && !lines[index].trim()) index += 1;
    let titleBlock = readWrappedMarkdownMark(lines, index, '**');
    if (!titleBlock.text) {
      titleBlock = readLifeMarkdownHeading(lines, index);
    }
    index = titleBlock.nextIndex;
    while (index < lines.length && !lines[index].trim()) index += 1;
    const subtitleBlock = readWrappedMarkdownMark(lines, index, '*');
    index = subtitleBlock.nextIndex;
    const blocks = parseLifeArticleBlocks(lines, index);
    articles.push({
      number,
      title: titleBlock.text,
      subtitle: subtitleBlock.text,
      blocks,
    });
  }
  return articles.slice(0, 6);
}

function renderLifeDaisy(index = 0) {
  const palette = [
    ['#fffaf3', '#d9adc4', '#d8a24a', '#fff6df'],
    ['#fff8fb', '#cfa6c4', '#cf9c48', '#fff1df'],
    ['#fffaf1', '#ddb49a', '#c9953d', '#fff5df'],
    ['#fff7ee', '#c3b1d8', '#d2a04a', '#fff3e8'],
    ['#fffaf4', '#abc6ad', '#cf9a43', '#fff6e6'],
    ['#fff7ef', '#e0aaba', '#c88f42', '#fff1e0'],
  ][index % 6];
  return `
    <svg class="life-daisy life-pearl-flower" viewBox="0 0 48 48" aria-hidden="true" focusable="false">
      <defs>
        <radialGradient id="lifePearl${index}" cx="35%" cy="30%" r="68%">
          <stop offset="0" stop-color="#ffffff"/>
          <stop offset="0.48" stop-color="${palette[3]}"/>
          <stop offset="1" stop-color="${palette[2]}"/>
        </radialGradient>
      </defs>
      <g fill="${palette[0]}" stroke="${palette[1]}" stroke-width="1.05" opacity="0.96">
        <ellipse cx="24" cy="9.8" rx="4.2" ry="7.7"/>
        <ellipse cx="24" cy="38.2" rx="4.2" ry="7.7"/>
        <ellipse cx="9.8" cy="24" rx="7.7" ry="4.2"/>
        <ellipse cx="38.2" cy="24" rx="7.7" ry="4.2"/>
        <ellipse cx="14.1" cy="14.1" rx="4.1" ry="7.1" transform="rotate(-45 14.1 14.1)"/>
        <ellipse cx="33.9" cy="33.9" rx="4.1" ry="7.1" transform="rotate(-45 33.9 33.9)"/>
        <ellipse cx="33.9" cy="14.1" rx="4.1" ry="7.1" transform="rotate(45 33.9 14.1)"/>
        <ellipse cx="14.1" cy="33.9" rx="4.1" ry="7.1" transform="rotate(45 14.1 33.9)"/>
      </g>
      <circle cx="24" cy="24" r="7.1" fill="url(#lifePearl${index})" stroke="${palette[1]}" stroke-width="0.9"/>
      <circle cx="21.4" cy="21.5" r="1.35" fill="rgba(255,255,255,0.82)"/>
    </svg>
  `;
}

