function flattenVisualText(value) {
  if (Array.isArray(value)) return value.map(flattenVisualText).join(' ');
  if (value && typeof value === 'object') return Object.values(value).map(flattenVisualText).join(' ');
  return String(value || '');
}

function normalizeKeywordVisualText(value) {
  return flattenVisualText(value)
    .toLocaleLowerCase('tr-TR')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/ı/g, 'i')
    .replace(/ğ/g, 'g')
    .replace(/ü/g, 'u')
    .replace(/ş/g, 's')
    .replace(/ö/g, 'o')
    .replace(/ç/g, 'c');
}

function includesAnyKeyword(text, keywords = []) {
  return keywords.some((keyword) => text.includes(keyword));
}

function inferKeywordCardVisualKey(value, fallback = 'medical') {
  const explicitText = value && typeof value === 'object'
    ? normalizeKeywordVisualText([
        value.categoryKey,
        value.sectionKey,
        value.parentKey,
        value.groupKey,
        value.collectionKey,
        value.sourcePage,
        value.slug,
        value.key,
      ].filter(Boolean).join(' '))
    : '';
  if (includesAnyKeyword(explicitText, ['genital-performans', 'genital performans', 'vajinal-estetik'])) return 'genital';
  if (includesAnyKeyword(explicitText, ['saglikli-hamilelik', 'hamilelik-yolu', 'pregnancy'])) return 'pregnancy';
  if (includesAnyKeyword(explicitText, ['kanser-ansiklopedisi', 'cancer-encyclopedia', 'onkoloji'])) return 'cancer';
  if (includesAnyKeyword(explicitText, ['hpv', 'kolposkopi'])) return 'hpv';
  if (includesAnyKeyword(explicitText, ['7den77', '7-den-77', 'yasam-rehberi', 'life'])) return 'life';

  const text = normalizeKeywordVisualText(value);
  if (includesAnyKeyword(text, ['saglikli-hamilelik', 'hamile', 'gebelik', 'gebe', 'dogum', 'doğum', 'postpartum', 'bebek', 'anne', 'folik', 'trimester', 'preterm', 'pregnan', 'birth', 'gravid', 'partum'])) return 'pregnancy';
  if (includesAnyKeyword(text, ['hpv', 'kolposkop', 'serviks', 'smear', 'leep', 'cin', 'asilama', 'aşı', 'papilloma', 'vph', 'virus', 'virüs'])) return 'hpv';
  if (includesAnyKeyword(text, ['kanser', 'onkoloji', 'cancer', 'carcinoma', 'tumor', 'tümör', 'over', 'ovarian', 'endometrium', 'rahim agzi', 'rahim ağzı', 'serviks kanseri', 'vulva', 'patoloji', 'figo', 'evre', 'evreleme', 'kemoterapi', 'radyoterapi'])) return 'cancer';
  if (includesAnyKeyword(text, ['cerrahi', 'surgery', 'surgical', 'laparoskop', 'robotik', 'histerektomi', 'minimal invaziv', 'mini invasiva', 'sentinel', 'biyopsi'])) return 'surgery';
  if (includesAnyKeyword(text, ['genital-performans', 'vajinal', 'vaginal', 'labioplasti', 'vulva', 'klitoral', 'perine', 'mons', 'cinsel', 'mahremiyet', 'estetik', 'konfor', 'pelvik', 'rf', 'lazer'])) return 'genital';
  if (includesAnyKeyword(text, ['7den77', '7 den 77', 'yasam', 'yaşam', 'menopoz', 'ergenlik', '20', '30', '40', '50', '60', '70', 'longevity', 'healthy', 'osteoporoz', 'kalp', 'metabolizma', 'beslenme'])) return 'life';
  return keywordCardVisualLibrary[fallback] ? fallback : 'medical';
}

function numericVisualSeed(value) {
  const flat = flattenVisualText(value);
  const match = flat.match(/\d+/);
  if (match) return Number.parseInt(match[0], 10);
  const text = normalizeKeywordVisualText(flat);
  let hash = 0;
  for (let index = 0; index < text.length; index += 1) {
    hash = ((hash << 5) - hash) + text.charCodeAt(index);
    hash |= 0;
  }
  return Math.abs(hash);
}

function pickKeywordCardVisual(value, fallback = 'medical', seed = 0) {
  const visualKey = inferKeywordCardVisualKey(value, fallback);
  const pool = keywordCardVisualLibrary[visualKey] || keywordCardVisualLibrary[fallback] || keywordCardVisualLibrary.medical;
  if (!pool?.length) return null;
  const resolvedSeed = Number.isFinite(seed) ? seed : numericVisualSeed(value);
  return pool[Math.abs(resolvedSeed) % pool.length] || pool[0];
}

function cardVisualMarkup(visual, className = 'card-photo-visual') {
  if (!visual?.src) return '';
  return `
    <span class="${escapeHtml(className)}" aria-hidden="true">
      <img src="${escapeHtml(visual.src)}" alt="${escapeHtml(visual.alt || '')}" loading="lazy" decoding="async" onerror="this.parentElement?.remove()" />
    </span>
  `;
}

