function normalizeLifeSearchText(value) {
  return String(value || '').toLocaleLowerCase('tr-TR');
}

function inferLifeEditorialTheme(block, article, slot) {
  const text = normalizeLifeSearchText(`${article?.title || ''} ${article?.subtitle || ''} ${block?.text || ''}`);
  const rules = [
    [/amh|yumurta|doğurgan|gebelik|fertil|ovary|ovarian|hamile|embriyo/i, 'ceramic'],
    [/cilt|skin|kolajen|estrogen|östrojen|saç|skincare/i, 'silk'],
    [/adet|kanama|cycle|regl|menstr|perimenopoz/i, 'pomegranate'],
    [/menopoz|uyku|hot flash|sıcak basması|gece/i, 'tea'],
    [/kemik|osteoporoz|d vitamini|kalsiyum|bone/i, 'stone'],
    [/kalp|metabolizma|kolesterol|tansiyon|heart|metabolic/i, 'olive'],
    [/mahremiyet|privacy|intimacy|utan|sınır|private/i, 'journal'],
    [/vajinal|vaginal|pelvik|pelvic|idrar|kuruluk|genital/i, 'shell'],
    [/hareket|egzersiz|kas|denge|düşme|movement|balance/i, 'leaf'],
    [/beslen|protein|ekmek|tohum|diyet|nutrition|diet/i, 'bread'],
    [/tarama|serviks|meme|kanser|hpv|screening|cancer/i, 'flower'],
    [/su|hidrasyon|böbrek|mesane|water|urinary/i, 'glass'],
  ];
  const match = rules.find(([pattern]) => pattern.test(text));
  if (match) {
    const baseIndex = Math.max(0, lifeEditorialThemes.findIndex((theme) => theme.key === match[1]));
    return lifeEditorialThemes[(baseIndex + slot) % lifeEditorialThemes.length] || lifeEditorialThemes[slot % lifeEditorialThemes.length];
  }
  return lifeEditorialThemes[slot % lifeEditorialThemes.length];
}

function pickLifePullQuote(text) {
  const sentences = cleanLifeText(text)
    .split(/(?<=[.!?])\s+/)
    .map((sentence) => sentence.trim())
    .filter((sentence) => sentence.length >= 42 && sentence.length <= 180);
  return sentences[0] || cleanLifeText(text).slice(0, 180);
}

function getLifeBreakIndexes(blocks = [], article = {}, decade = healthyDecadeDefinitions[0]) {
  const paragraphs = blocks
    .map((block, index) => ({ block, index }))
    .filter((item) => item.block.type === 'paragraph' && item.block.text.length > 120);
  if (paragraphs.length < 3) return [];
  const globalArticleIndex = ((decade.marker - 1) * 6) + Math.max(0, (article.number || 1) - 1);
  const breakCount = globalArticleIndex % 3 === 0 ? 4 : 3;
  const ratioStops = breakCount === 4 ? [0.18, 0.42, 0.66, 0.86] : [0.24, 0.52, 0.78];
  return ratioStops
    .map((ratio) => paragraphs[Math.min(paragraphs.length - 1, Math.max(0, Math.round((paragraphs.length - 1) * ratio)))].index)
    .filter((value, index, all) => all.indexOf(value) === index)
    .slice(0, breakCount);
}

function renderLifeEditorialBreak(block, article, decade, breakIndex) {
  const slot = ((((decade.marker - 1) * 6) + Math.max(0, (article.number || 1) - 1)) * 4 + breakIndex) % 120;
  const theme = inferLifeEditorialTheme(block, article, slot);
  const quote = pickLifePullQuote(block.text);
  return `
    <figure class="life-editorial-break" data-theme="${escapeHtml(theme.key)}" style="--life-photo-tilt: ${breakIndex % 2 === 0 ? '-0.8deg' : '0.8deg'}; --life-photo-url: url('${escapeHtml(theme.image || '')}');">
      <div class="life-editorial-photo" role="img" aria-label="${escapeHtml(theme.label)}">
        <span></span>
      </div>
      <blockquote>${escapeHtml(quote)}</blockquote>
    </figure>
  `;
}

function renderLifeArticleBlocks(blocks = [], article = {}, decade = healthyDecadeDefinitions[0]) {
  const breakIndexes = getLifeBreakIndexes(blocks, article, decade);
  let breakCounter = 0;
  return blocks
    .map((block, index) => {
      let html = '';
      if (block.type === 'heading') html = `<h3>${escapeHtml(block.text)}</h3>`;
      else if (block.type === 'quote') html = `<p class="life-opening">${escapeHtml(block.text)}</p>`;
      else if (block.type === 'note') html = `<aside class="life-doctor-note">${escapeHtml(block.text)}</aside>`;
      else html = `<p>${escapeHtml(block.text)}</p>`;
      if (breakIndexes.includes(index)) {
        html += renderLifeEditorialBreak(block, article, decade, breakCounter);
        breakCounter += 1;
      }
      return html;
    })
    .join('');
}

function getHealthyDecadeDefinition(decadeKey = activeHealthyDecadeKey) {
  return healthyDecadeDefinitions.find((item) => item.key === decadeKey) || healthyDecadeDefinitions[0];
}

function getLifeContentLanguageKey(language = activeLanguage, decadeKey = activeHealthyDecadeKey) {
  if (lifeArticlesRemoteUrl && translations[language]) return language;
  return lifeMarkdownUrls[language]?.[decadeKey] ? language : 'tr';
}

function getHealthyDecadeLabel(language = activeLanguage, decade = getHealthyDecadeDefinition()) {
  const cardIndex = healthyDecadeDefinitions.findIndex((item) => item.key === decade.key);
  const t = translations[language] || translations.tr;
  return t.healthyContentCards?.[cardIndex]?.[0] || translations.tr.healthyContentCards[cardIndex]?.[0] || decade.key;
}

function getHealthyDecadeTitle(language = activeLanguage, decade = getHealthyDecadeDefinition()) {
  if (decade.key === '20s') {
    const labels = getHealthyContentUi(language);
    return labels.twentiesTitle || getHealthyDecadeLabel(language, decade);
  }
  return getHealthyDecadeLabel(language, decade);
}

function loadLifeArticles(language = activeLanguage, decadeKey = activeHealthyDecadeKey) {
  const decade = getHealthyDecadeDefinition(decadeKey);
  const languageKey = getLifeContentLanguageKey(language, decade.key);
  const cacheKey = `${languageKey}:${decade.key}`;
  const source = lifeMarkdownUrls[languageKey]?.[decade.key] || lifeMarkdownUrls.tr[decade.key];
  if (lifeArticlesCache[cacheKey]) return Promise.resolve(lifeArticlesCache[cacheKey]);
  if (!lifeArticlesPromises[cacheKey]) {
    const loadFromSource = () => fetch(source, { cache: 'no-store' })
      .then((response) => {
        if (response.ok) return response.text();
        if (languageKey !== 'tr') {
          return fetch(lifeMarkdownUrls.tr[decade.key], { cache: 'no-store' }).then((fallbackResponse) => {
            if (!fallbackResponse.ok) throw new Error('life-markdown-not-found');
            return fallbackResponse.text();
          });
        }
        throw new Error('life-markdown-not-found');
      })
      .then((markdown) => {
        lifeArticlesCache[cacheKey] = parseLifeMarkdown(markdown, decade.marker);
        return lifeArticlesCache[cacheKey];
      });
    if (lifeArticlesRemoteUrl) {
      if (!lifeArticlesRemotePromise) {
        lifeArticlesRemotePromise = fetch(lifeArticlesRemoteUrl, { cache: 'force-cache' }).then((response) => {
          if (!response.ok) throw new Error('life-articles-remote-not-found');
          return response.json();
        });
      }
      lifeArticlesPromises[cacheKey] = lifeArticlesRemotePromise
        .then((bundle) => {
          const markdown = bundle?.[languageKey]?.[decade.key] || bundle?.tr?.[decade.key];
          if (!markdown) throw new Error('life-articles-remote-entry-not-found');
          lifeArticlesCache[cacheKey] = parseLifeMarkdown(markdown, decade.marker);
          return lifeArticlesCache[cacheKey];
        })
        .catch(loadFromSource);
    } else {
      lifeArticlesPromises[cacheKey] = loadFromSource();
    }
  }
  return lifeArticlesPromises[cacheKey];
}

function scrollHealthyContentIntoView() {
  document.getElementById('yasam-rehberi')?.scrollIntoView({ block: 'start', behavior: 'smooth' });
}

function renderHealthyDecadeCards(language) {
  const t = translations[language] || translations.tr;
  const labels = getHealthyContentUi(language);
  const grid = document.querySelector('.healthy-content-cards');
  const section = document.getElementById('yasam-rehberi');
  if (!grid) return;
  section?.classList.remove('is-life-list', 'is-life-reader');
  grid.innerHTML = (t.healthyContentCards || translations.tr.healthyContentCards)
    .map((item, index) => {
      const decade = healthyDecadeDefinitions[index] || healthyDecadeDefinitions[0];
      const visual = getLifeDecadeVisual(decade);
      return `
        <button class="healthy-decade-card" type="button" data-life-decade="${escapeHtml(decade.key)}">
          ${renderLifeCardVisual(visual)}
          <span class="healthy-decade-label">${escapeHtml(t.healthyContentKicker || translations.tr.healthyContentKicker)}</span>
          <h3>${escapeHtml(item[0])}</h3>
          <p>${escapeHtml(item[1])}</p>
          <em>${escapeHtml(labels.open || translations.tr.healthyContentUi.open)}</em>
        </button>
      `;
    })
    .join('');
  grid.querySelectorAll('[data-life-decade]').forEach((button) => {
    button.addEventListener('click', () => {
      activeHealthyDecadeKey = button.dataset.lifeDecade || '20s';
      activeHealthyContentView = 'list';
      activeHealthyArticleIndex = null;
      renderHealthyContent(language);
      scrollHealthyContentIntoView();
    });
  });
}

function renderHealthyAgeList(language, articles) {
  const labels = getHealthyContentUi(language);
  const previousMenuLabel = getPreviousMenuLabel(language);
  const decade = getHealthyDecadeDefinition();
  const decadeLabel = getHealthyDecadeLabel(language, decade);
  const decadeTitle = getHealthyDecadeTitle(language, decade);
  const grid = document.querySelector('.healthy-content-cards');
  const section = document.getElementById('yasam-rehberi');
  if (!grid) return;
  section?.classList.add('is-life-list');
  section?.classList.remove('is-life-reader');
  grid.innerHTML = `
    <div class="life-twenties-panel life-age-panel">
      <div class="life-levelbar">
        <button type="button" class="life-back" data-life-back-decades>← ${escapeHtml(previousMenuLabel)}</button>
        <div>
          <span>${escapeHtml(decadeLabel)}</span>
          <strong>${escapeHtml(decadeTitle)}</strong>
          <p>${escapeHtml(labels.ageGroupText || labels.twentiesText || translations.tr.healthyContentUi.ageGroupText)}</p>
        </div>
      </div>
      <div class="life-article-grid">
        ${articles.map((article, index) => `
          <button type="button" class="life-article-card" data-life-article-index="${index}">
            ${renderLifeCardVisual(getLifeArticleVisual(article, decade, index), 'life-card-visual life-article-visual')}
            <span class="life-article-copy">
              <h3>${escapeHtml(article.title)}</h3>
              <em>${escapeHtml(labels.open || translations.tr.healthyContentUi.open)}</em>
            </span>
          </button>
        `).join('')}
      </div>
    </div>
  `;
  grid.querySelector('[data-life-back-decades]')?.addEventListener('click', () => {
    activeHealthyContentView = 'decades';
    activeHealthyArticleIndex = null;
    renderHealthyContent(language);
  });
  grid.querySelectorAll('[data-life-article-index]').forEach((button) => {
    button.addEventListener('click', () => {
      activeHealthyContentView = 'article';
      activeHealthyArticleIndex = Number.parseInt(button.dataset.lifeArticleIndex, 10);
      renderHealthyContent(language);
      scrollHealthyContentIntoView();
    });
  });
}

function renderHealthyArticle(language, article) {
  const labels = getHealthyContentUi(language);
  const decade = getHealthyDecadeDefinition();
  const decadeLabel = getHealthyDecadeLabel(language, decade);
  const decadeTitle = getHealthyDecadeTitle(language, decade);
  const backLabel = getPreviousMenuLabel(language);
  const grid = document.querySelector('.healthy-content-cards');
  const section = document.getElementById('yasam-rehberi');
  if (!grid || !article) return;
  section?.classList.remove('is-life-list');
  section?.classList.add('is-life-reader');
  grid.innerHTML = `
    <article class="life-reader">
      <button type="button" class="life-back" data-life-back-age>← ${escapeHtml(backLabel)}</button>
      <p class="life-reader-kicker">${escapeHtml(decadeLabel)} · ${escapeHtml(decadeTitle)}</p>
      <h2>${escapeHtml(article.title)}</h2>
      ${article.subtitle ? `<p class="life-reader-subtitle">${escapeHtml(article.subtitle)}</p>` : ''}
      <div class="life-reader-body">${renderLifeArticleBlocks(article.blocks, article, decade)}</div>
    </article>
  `;
  grid.querySelectorAll('[data-life-back-age]').forEach((button) => {
    button.addEventListener('click', () => {
      activeHealthyContentView = 'list';
      activeHealthyArticleIndex = null;
      renderHealthyContent(language);
      scrollHealthyContentIntoView();
    });
  });
}

function renderHealthyContent(language = activeLanguage) {
  const labels = getHealthyContentUi(language);
  const grid = document.querySelector('.healthy-content-cards');
  if (!grid) return;
  if (activeHealthyContentView === 'decades') {
    renderHealthyDecadeCards(language);
    return;
  }
  grid.innerHTML = `<div class="life-loading">${escapeHtml(labels.loading)}</div>`;
  loadLifeArticles(language, activeHealthyDecadeKey)
    .then((articles) => {
      if (activeHealthyContentView === 'article') {
        renderHealthyArticle(language, articles[activeHealthyArticleIndex]);
        return;
      }
      renderHealthyAgeList(language, articles);
    })
    .catch(() => {
      grid.innerHTML = `<div class="life-loading is-error">${escapeHtml(labels.error)}</div>`;
    });
}

const hpvSourceLinks = [
  { label: 'CDC · HPV vaccination recommendations', url: 'https://www.cdc.gov/hpv/hcp/vaccination-considerations/index.html' },
  { label: 'CDC · Cervical cancer prevention', url: 'https://www.cdc.gov/cervical-cancer/prevention/index.html' },
  { label: 'ACOG · Cervical cancer screening guidance', url: 'https://www.acog.org/clinical/clinical-guidance/practice-advisory/articles/2021/04/updated-cervical-cancer-screening-guidelines' },
  { label: 'ACOG · Patient-collected HPV sampling update', url: 'https://www.acog.org/news/news-releases/2026/04/acog-publishes-updated-cervical-cancer-screening-guidance' },
  { label: 'NCI · Cervical cancer causes, risk and prevention', url: 'https://www.cancer.gov/types/cervical/causes-risk-prevention' },
];

let activeHpvArticleIndex = null;

const hpvDocxTrCards = [{"title":"HPV Nedir","preview":"İnsan papilloma virüsü, 200'den fazla tipi olan bir DNA virüsüdür. Yaklaşık 14 tipi yüksek risklidir --- persistan kaldıklarında kanser öncesi değişikliklere zemin hazırlar. HPV 16 ve 18 serviks kanserlerinin yaklaşık %70'inden sorumludur.","bodyHtml":"<h4>Yapısı ve sınıflandırması</h4><p>HPV, 200&#x27;den fazla genotipi olan ikosahedral simetrili bir DNA virüsüdür. Klinik ilgilendiren grupları iki kümeye ayrılır:</p><ul><li>Yüksek riskli tipler (~14 adet): HPV 16, 18, 31, 33, 45, 52, 58 başlıca. Persistan kaldıklarında serviks, vulva, vajina, anüs, penis ve orofaringeal kanser zemini hazırlarlar.</li><li>Düşük riskli tipler: HPV 6 ve 11 başlıca. Genital siğil (kondiloma akümine) ile ilişkili, kanser yapmazlar.</li></ul><h4>Bulaş yolu</h4><p>HPV cinsel temas --- vajinal, anal, oral --- ile bulaşır. Prezervatif riski azaltır ama tamamen ortadan kaldırmaz, çünkü prezervatifin örtmediği genital cilt teması bulaş için yeterlidir. Çok nadir vertikal (anneden bebeğe doğum sırasında) bulaş laringeal papillomatozis ile ilişkilendirilmiştir.</p><h4>Doğal seyir</h4><p>Cinsel olarak aktif kadınların yaklaşık %75-80&#x27;i hayatlarının bir döneminde HPV ile karşılaşır. Çoğu enfeksiyon (~%90) bağışıklık sistemi tarafından 1-2 yıl içinde temizlenir. Geriye persistan kalan azınlık klinik takip gerektirir --- kanser gelişimi yıllarca süren bir süreçtir, bu yüzden erken yakalama mümkündür.</p>","visual":false},{"title":"Tarama: Ne zaman, nasıl","preview":"Türkiye'de KETEM programı 30 yaş üzeri kadınlara 5 yılda bir ücretsiz HPV testi sunar. 2024'ten itibaren self-collection yöntemleri de FDA onaylı --- evde örnekleme dönemi başlıyor.","bodyHtml":"<h4>Standart tarama protokolü</h4><ul><li>21--29 yaş: 3 yılda bir Pap smear</li><li>30--65 yaş: 5 yılda bir HPV testi veya ko-test (HPV + smear birlikte)</li><li>65 yaş üstü: önceki 10 yıl temiz tarama varsa kesilebilir</li></ul><h4>Türkiye Sağlık Bakanlığı KETEM</h4><p>KETEM (Kanser Erken Teşhis Tarama ve Eğitim Merkezleri) programı kapsamında 30 yaş üzeri kadınlara 5 yılda bir ücretsiz HPV testi yapılıyor. Türkiye&#x27;de yılda yaklaşık 2.500 yeni serviks kanseri tanısı konuyor --- bu sayı düzenli tarama ile dramatik azaltılabilir.</p><h4>Self-collection: yeni dönem</h4><p>FDA 2024&#x27;te klinikte hasta tarafından alınan vajinal sürüntü ile HPV testini onayladı. 2025&#x27;te Teal Wand evde örnekleme cihazını onayladı. American Cancer Society Aralık 2025 kılavuzlarında self-collection&#x27;ı opsiyonel olarak kabul etti. Türkiye&#x27;de henüz rutin uygulamada değil ama yakın gelecekte beklenir.</p><h4>Ko-test mantığı</h4><p>HPV testi virüsün varlığını gösterir; smear ise hücresel değişiklikleri. Birlikte uygulandığında tanı doğruluğu maksimum. Smear normal + HPV negatif → 5 yıl güvenli aralık. Anormal sonuç → kolposkopi planlanır.</p><h4>Risk grubunda daha sık tarama</h4><p>HIV pozitif, immün baskılanmış, organ nakli alıcısı, daha önce CIN 2/3 öyküsü olanlarda tarama aralığı kısalır. Kişisel risk profilinize göre planlanır.</p>","visual":false},{"title":"HPV Aşısı: Yaşa göre doğru şema","preview":"DSÖ bazı programlarda tek doz seçeneğini destekler; CDC ve ACOG ise yaşa ve bağışıklık durumuna göre iki veya üç dozluk şema önerir. Aşı mevcut enfeksiyonu tedavi etmez, yeni enfeksiyonlara karşı koruma sağlar.","bodyHtml":"<h4>Doz şeması nasıl okunmalı?</h4><p>HPV aşısında en güvenli dil, tek bir rakama kilitlenmek değil; yaş, bağışıklık durumu ve ülkenin güncel kılavuzunu birlikte okumaktır. DSÖ bazı toplum sağlığı programlarında tek doz veya iki doz seçeneğini desteklerken, CDC ve ACOG bireysel klinik uygulamada başlangıç yaşına ve bağışıklık durumuna göre iki ya da üç dozluk şemaları tanımlar. Bu nedenle kişisel plan güncel kılavuz, yaş, daha önceki aşılanma durumu ve hekim değerlendirmesiyle yapılmalıdır.</p><h4>Yaş aralıkları</h4><ul><li>9--14 yaş: ideal aralık. İlk cinsel temastan önce maksimum koruma.</li><li>15--26 yaş: catch-up dönemidir; başlanacak doz sayısı ve aralıklar güncel kılavuza göre belirlenir.</li><li>27--45 yaş: bireysel değerlendirme gerekir; fayda olası yeni maruziyet, önceki HPV öyküsü ve kişisel riskle birlikte konuşulur.</li></ul><h4>Türkiye&#x27;de aşı durumu</h4><p>HPV aşısı Türkiye Sağlık Bakanlığı&#x27;nın rutin aşı takviminde değil --- özel uygulanır. Gardasil-9 piyasada mevcut, dokuz tipi (6, 11, 16, 18, 31, 33, 45, 52, 58) kapsar. Maliyet kuruma, tarihe ve tedarik koşullarına göre değişebilir; güncel bilgi uygulama yapılacak kurum veya eczaneden doğrulanmalıdır.</p><h4>Sık yanlış inanış</h4><p>&quot;Aşı oldum, artık taranmama gerek yok.&quot; Yanlış. Aşı yüksek riskli tiplerin BİR KISMINA karşı koruma sağlar; %100 tüm tipleri kapsamaz. Aşılı kadınlar da yaşa uygun tarama programını sürdürmelidir. Ancak aşılı kohortlarda anormal smear ve kolposkopi ihtiyacı belirgin azalmaktadır.</p><h4>Tedavi etmez, korur</h4><p>Aşı, mevcut HPV enfeksiyonunu temizlemez --- siğili veya persistan enfeksiyonu olan kadında tedavi etkisi yoktur. Henüz karşılaşılmamış tiplere karşı koruyucu rolü vardır.</p>","visual":false},{"title":"HPV Pozitifim — Sırada Ne Var","preview":"HPV pozitif sonucu kanser değil, takip işaretidir. Yaklaşım sonucun tipine göre değişir; çoğu zaman 12 ay sonra tekrar test, gerekirse kolposkopi.","bodyHtml":"<h4>Sonuç tipine göre yol</h4><ul><li>Düşük riskli HPV (6, 11): genital siğil tedavisi gerekiyorsa planlanır; kanser riski yok.</li><li>Yüksek riskli HPV --- smear normal: 12 ay sonra ko-test tekrarı.</li><li>Yüksek riskli HPV --- smear anormal: kolposkopi gerekir; gerekirse hedefli biyopsi.</li><li>HPV 16 veya 18 pozitif: doğrudan kolposkopi düşünülür (en yüksek riskli iki tip).</li></ul><h4>Persistan enfeksiyon nedir</h4><p>Aynı yüksek riskli HPV tipinin 12 ay veya daha uzun süre devam etmesi persistan enfeksiyon olarak kabul edilir. Çoğu serviks kanseri persistan enfeksiyon zemininde yıllar içinde gelişir. Ancak doğru takiple kanser öncesi (CIN 2-3) seviyede yakalanıp tedavi edilebilir --- kanseri önleyebilen tek mekanizma budur.</p><h4>Korkmadan eyleme geçmek</h4><p>HPV pozitifliği yaşam tarzı, sadakat veya hijyen sorgusu DEĞİLDİR. Aktif cinsel yaşamı olan çoğu insanda hayatın bir döneminde görülür. Eyleme geçmek için doğru bilgi, doğru takip planı, doğru klinik ekip yeterlidir.</p><h4>Bağışıklık sistemini desteklemek</h4><p>HPV&#x27;yi sonuçta vücudunuz temizler. Klinik takip dışında destekleyici yaklaşımlar:</p><ul><li>Sigara: HPV temizlenmesini geciktirir; bırakmak öncelikli.</li><li>Vajinal mikrobiyota: Lactobacillus crispatus baskınlığı temizlenmeyi hızlandırır.</li><li>Bağışıklık: D vitamini, çinko, uyku, stres yönetimi.</li><li>Düzenli kontrol: panik değil, takvim.</li></ul>","visual":true},{"title":"Kolposkopi ve LEEP","preview":"Anormal smear veya HPV testinde kolposkopi yapılır: serviksin yüksek büyütmeli optik incelemesi. Yüksek dereceli lezyon (CIN 2-3) çıkarsa LEEP ile etkilenen doku çıkarılır.","bodyHtml":"<h4>Kolposkopi --- ne, nasıl</h4><p>Kolposkopi, serviksin yüksek büyütmeli optik bir cihazla incelendiği ofis prosedürüdür. Asetik asit veya Lugol solüsyonu ile boyama, anormal alanları görünür kılar. Ağrısızdır, yaklaşık 10-15 dakika sürer. Şüpheli alanlardan hedefli biyopsi alınabilir.</p><h4>Endikasyonlar</h4><ul><li>Yüksek riskli HPV (özellikle 16, 18) pozitif</li><li>Anormal smear (ASC-US ile HPV+, LSIL, HSIL)</li><li>Görünür servikal lezyon</li><li>Persistan HPV pozitifliği</li></ul><h4>Biyopsi sonuçlarına göre</h4><ul><li>CIN 1: çoğunlukla takip yeterli; çoğu kendiliğinden geriler</li><li>CIN 2: bireysel değerlendirme --- yaş, gebelik planı, lezyon büyüklüğü</li><li>CIN 3: tedavi gereklidir --- LEEP veya konizasyon</li></ul><h4>LEEP --- ne demek</h4><p>LEEP (Loop Electrosurgical Excision Procedure) elektrocerrahi ile etkilenen doku şeridini çıkarır. Ofis koşullarında lokal anestezi altında 10-15 dakikada yapılır. Doğru endikasyonla uygulandığında serviks kanserinin önlenmesinde altın standarttır.</p><h4>LEEP ve gebelik</h4><p>Standart bir LEEP gelecek gebeliklerde ciddi sorun yaratmaz. Ancak çok geniş konizasyon veya tekrarlayan LEEP&#x27;ler servikal yetmezlik riskini artırabilir. Bu yüzden endikasyon her vakada özen ister --- gereksiz LEEP&#x27;ten kaçınmak da gereksiz kanseri kaçırmak kadar önemlidir.</p><h4>İyileşme</h4><p>LEEP sonrası 4-6 hafta cinsel ilişki, tampon, vaginal duş ve ağır kaldırma önerilmez. Hafif kanama ve akıntı normaldir. 6 ay sonra ilk kontrol, sonrasında HPV+smear takibi yıllık devam eder.</p>","visual":false},{"title":"Genital Siğil — Kondiloma Akümine","preview":"Düşük riskli HPV tiplerinin (özellikle 6 ve 11) yol açtığı kanser yapmayan, ancak görünür ve tekrarlayıcı lezyonlar. Doğru tedaviyle kontrol edilebilir; takip protokolü tedavi kadar önemli.","bodyHtml":"<h4>Tanım ve Epidemiyoloji</h4><p>Genital siğil (kondiloma akümine), düşük riskli HPV tiplerinin --- başlıca HPV 6 ve HPV 11 --- neden olduğu, genital ve anal bölgenin iyi huylu lezyonlarıdır. Vakaların yaklaşık %90&#x27;ı bu iki tipten kaynaklanır. Kanser yapmazlar --- bu vurgu önemlidir, çünkü tanı sıklıkla &quot;kanser olur muyum?&quot; sorusuyla gelir. Cevap: hayır.</p><p>Ancak siğiller iyi huylu olmaları, sorunsuz oldukları anlamına gelmez. Görünür, bulaşıcı, tekrarlayıcıdırlar; bedensel ve ruhsal yük getirirler. Aktif cinsel yaşam içindeki kişilerde ömür boyu prevalans %5-10 aralığında tahmin edilir.</p><h4>Klinik görünümler --- dört alt tip</h4><p>Tüm genital siğiller aynı görünmez. Klinik pratikte dört ana form ayırt edilir:</p><ul><li>Akümine (klasik) --- sivri uçlu, karnabahar görünümünde, yumuşak; en sık form.</li><li>Papüler --- küçük, yuvarlak, cilt renginde, çıkıntı küçük.</li><li>Düz (flat) --- az çıkıntılı, gözden kaçabilir; özellikle servikal yerleşimli olanlar --- çoğu zaman sadece kolposkopi ile fark edilir.</li><li>Keratotik --- kalın, sert, kuru genital cilt alanlarında (pubis, perine kenarı); diğer formlardan ayırıcı tanı önemlidir.</li></ul><h4>Yerleşim</h4><p>Kadında en sık: vulva (özellikle labia minora), perineal bölge, periüretral, perianal, vajina, serviks. Erkekte: penis cildi (özellikle frenulum, glans), skrotum, perine, anal bölge. Oral kavite yerleşimi nadirdir ama mümkündür (özellikle oral seks bulaşı sonrası).</p><p>Subklinik form --- yani çıplak gözle görünmeyen ama asetik asit uygulamasıyla beyazlaşan lezyonlar --- sıklıkla mevcuttur. Bu yüzden &quot;sadece görüleni temizledim&quot; yaklaşımı yetersiz olabilir.</p><h4>Tanı</h4><p>Çoğu vakada tanı kliniktir --- yani gözle muayene yeterlidir. Ancak şu durumlarda biyopsi gerekir:</p><ul><li>Atipik görünüm: büyük, ülsere, sertleşmiş, kanayan veya hızlı büyüyen lezyon</li><li>Standart tedaviye direnç</li><li>İmmün baskılanmış hastalar</li><li>Yüksek dereceli skuamöz lezyon şüphesi</li></ul><p>Asetik asit testi (%3-5&#x27;lik solüsyon ile uygulanan) gri zone vakalarda yardımcıdır --- anormal alanlar beyazlaşır. Kolposkopi servikal yerleşimde standart araçtır.</p><h4>Tedavi seçenekleri --- geniş palet</h4><h4>A · Hasta tarafından evde uygulanır</h4><ul><li>İmikuimod %5 krem: haftada 3 gece, 16 hafta. Bağışıklık modülatörü; lokal etki.</li><li>Podofilotoksin %0.5 solüsyon/jel: 3 gün uygula, 4 gün ara --- 4 hafta. Mitotik durdurucu.</li><li>Sinekateşin %15 merhem (yeşil çay özütü): günde 3 kez, 16 hafta. Biyolojik antiviral.</li></ul><h4>B · Klinikte hekim tarafından uygulanır</h4><ul><li>Kriyoterapi (sıvı azot): -196°C ile dondurma, çoğu lezyonda 2-3 seans. Çok yaygın, ofis prosedürü.</li><li>Triklor asetik asit (%80-90): kimyasal kostik, küçük lezyonlar için. Düzenli kontrolde uygulanır.</li><li>Elektrocerrahi (elektrokoter): büyük veya rezistan lezyonlarda. Lokal anestezi altında.</li><li>Lazer (CO2): geniş yayılımlı, anatomik olarak hassas yerleşimlerde --- özellikle anorektal.</li><li>Cerrahi eksizyon: çok büyük (&gt;2 cm) veya cerrahi açıdan zor lezyonlarda.</li></ul><h4>Tedavi seçimi nasıl yapılır</h4><p>Tek doğru yöntem yok. Karar şu faktörlere göre verilir: lezyon büyüklüğü, sayısı, yerleşimi, hastanın tercihi, gebelik durumu, immün durum, finansal kaynaklar, lojistik. İdeal olan kişiye özel plandır --- bazen iki yöntemin kombinasyonu, bazen aşamalı yaklaşım.</p><h4>Başarı oranları ve tekrarlama</h4><p>İlk tedavi sonrası klinik temizlik yaklaşık %50-70 aralığındadır. Tekrarlama (3 ay içinde) %25-50. Bu rakamlar düşük gelmesin --- siğil tedavisinde &quot;ilk seferde tamamen biter&quot; beklentisi gerçekçi değildir. Tekrarlama tedavi başarısızlığı değil, hastalığın doğasıdır. Önemli olan tekrarlamayı yakalamak ve tekrar tedavi etmek.</p><h4>Özel durumlar</h4><h4>Gebelik</h4><p>İmikuimod, podofilotoksin, sinekateşin gebelikte kullanılmaz. Güvenli seçenekler: kriyoterapi, TCA, gerektiğinde cerrahi eksizyon. Doğum öncesi temizlik önerilir --- perinatal bulaş çok nadir ama mümkündür ve laringeal papillomatozis (bebekte) ile ilişkilidir. Sezaryen sadece doğum kanalını mekanik tıkayan büyük lezyonlarda düşünülür, rutin değildir.</p><h4>İmmün baskılanmış hastalar</h4><p>HIV pozitif, transplant alıcısı, kemoterapi alan hastalarda lezyonlar daha agresif, daha rezistan, daha sık tekrarlayıcıdır. Bu grupta yüksek dereceli displazi/anal kanser riski de artar --- anal sitoloji rutin düşünülmelidir.</p><h4>Anorektal yerleşim</h4><p>Anal kanal yerleşimli lezyonlar dış genital lezyonlar kadar yaygındır ama gözden kaçar. Yüksek riskli grupta (HIV+, anal cinsel temas) anal sitoloji ve gerektiğinde yüksek çözünürlüklü anoskopi (HRA) düşünülür.</p><h4>Aşılamanın rolü</h4><p>HPV aşısı (Gardasil-9) zaten siğili olan kişiyi tedavi etmez. Ancak iki nokta önemlidir:</p><ul><li>Henüz maruz kalmadığınız diğer HPV tiplerine karşı korur --- yeni siğil ve yüksek riskli enfeksiyon önlenebilir.</li><li>Tekrarlama riskini azalttığına dair sınırlı ama umut verici veri var --- özellikle aşılı kişilerde re-enfeksiyon ve tekrarlayan siğil daha az.</li></ul><h4>Eş ve cinsel partner</h4><p>Yaygın yanlış: &quot;Eşim de muayene olsun, o da tedavi olsun, sonra kuralım.&quot; Gerçek: eş muayenesi tek başına partneri &quot;temizlemez&quot; --- eğer onda da görünür siğil yoksa tedavi gerekmez. HPV taşıyıcılığı görünür değil; eşin negatif görünümü taşımadığı anlamına gelmez. Pratik yaklaşım:</p><ul><li>Eşte görünür siğil varsa tedavi edilir.</li><li>Açık iletişim kurulur --- utanç değil, ortak yolculuk.</li><li>Yeni partner ile prezervatif tekrarlamayı azaltır ama tamamen önlemez.</li><li>Eşin de HPV aşısı (Gardasil-9) düşünülmeli --- özellikle 26 yaş altıysa öncelikli.</li></ul><h4>Psikolojik boyut</h4><p>Tanı çoğu zaman utanç, korku, sadakatsizlik suçlaması (kendine veya partnere), cinsel hayatın bozulması ile gelir. Bu duygular normaldir ve klinik takipte ihmal edilmemelidir. Pratik çerçeve:</p><ul><li>HPV cinsel olarak aktif çoğu insanda hayatın bir döneminde görülür --- istatistik bilmek korkuyu hafifletir.</li><li>Sadakat sorgusu yersizdir --- virüs yıllarca latent kalabilir; bugünkü tanı bugünkü bulaş anlamına gelmez.</li><li>İhtiyaç duyulduğunda psikolog/cinsel sağlık danışmanı yönlendirmesi premium klinik bakımın parçasıdır.</li></ul><h4>Takip protokolü</h4><ul><li>Tedavi sonrası ilk 3 ay aylık kontrol</li><li>3-6 ay: 6 haftada bir</li><li>6 ay temiz → yıllık standart kontrole dönüş</li><li>HPV + smear taraması yaşa uygun aralıkta sürdürülür</li></ul><h4>Ne zaman uzmanı görmeli</h4><p>Genital siğil çoğu kez aile hekimi veya genel jinekolog tarafından yönetilebilir. Şu durumlarda jinekolojik onkoloji uzmanına yönlendirme gerekir:</p><ul><li>Standart tedaviye dirençli vakalar</li><li>Servikal yerleşim şüphesi (kolposkopi gerektirir)</li><li>Atipik görünüm --- kanser ayırıcı tanısı şart</li><li>Tekrarlayan veya aşırı yaygın lezyonlar</li><li>Gebelik ile birlikte</li><li>İmmün baskılanma zemininde</li></ul>","visual":false},{"title":"Vajinal Mikrobiyota ve HPV","preview":"Aktif araştırma alanlarımdan biri. Lactobacillus crispatus baskın mikrobiyota HPV temizlenmesini hızlandırır; disbiyoz persistan enfeksiyon riskini artırır. Probiyotik ve yaşam tarzı klinik takibe destek olur --- onun yerine geçmez.","bodyHtml":"<h4>Mikrobiyota nedir</h4><p>Vajinal mikrobiyota, vajinanın içinde yaşayan bakteri topluluğudur. Sağlıklı bir kadında çoğunlukla Lactobacillus türleri baskındır --- bunlar laktik asit üreterek vajinal pH&#x27;ı düşük (3.8-4.5) tutar ve patojenleri uzakta tutar.</p><h4>Lactobacillus crispatus etkisi</h4><p>Beş ana vajinal community state type (CST) tanımlanmıştır. Bunlardan CST-I (L. crispatus baskın) HPV temizlenmesi açısından en iyi profili oluşturur. CST-IV (anaerobik bakteriler baskın, disbiyoz) ise persistan HPV ve servikal displazi riski ile ilişkilidir. Bu ilişki yıllar içinde birikmiş kohort verisiyle güçlenmiştir.</p><h4>Klinik pratikteki kullanım</h4><ul><li>Persistan HPV vakalarında vajinal pH ve mikrobiyota değerlendirmesi</li><li>L. crispatus + L. brevis içeren probiyotik desteği (kanıta göre kişiselleştirilmiş)</li><li>Yaşam tarzı: hijyen ürünleri, antibiyotik kullanımı, beslenme --- mikrobiyotayı koruyan günlük seçimler</li><li>Klinik araştırmalarımda L:D laktik asit izoform oranı izlenir --- HPV temizlenmesinin potansiyel öngörü belirtecidir</li></ul><h4>Kanıt seviyesi şeffaflığı</h4><p>Probiyotik destek HPV tedavisinde kılavuz tedavinin yerini almaz. Cerrahi, kolposkopi, LEEP gerektiğinde yapılır. Mikrobiyota desteği yan yola eklenir, ana yola değil. Bu önemli bir ayrım --- fonksiyonel yaklaşım kanıta dayalı tıbbın &quot;yerine&quot; değil, &quot;yanında&quot; çalışır.</p>","visual":false},{"title":"Erkeklerde HPV","preview":"HPV cinsiyetsizdir. Erkek de taşır, bulaştırır, hastalanır. Orofaringeal kanser, anal kanser, penis kanseri ile ilişkilidir. Erkek aşılaması ABD ve Avrupa'da rutin; Türkiye'de henüz değil ama özel uygulanabilir.","bodyHtml":"<h4>Erkekte HPV ilişkili kanserler</h4><ul><li>Orofaringeal kanser (boğaz, bademcik, dil kökü): %70 HPV ilişkili. Son 20 yılda Batı&#x27;da artış halinde --- sigara/alkol kaynaklı orofaringeal kanseri geçti.</li><li>Anal kanser: %85 HPV ilişkili. Erkekte kadına göre daha az ama HIV+ veya MSM popülasyonda risk yüksek.</li><li>Penis kanseri: %50 HPV ilişkili. Nadir ama önlenebilir.</li></ul><h4>Erkek aşılaması</h4><p>Aşı erkekte de yüksek etkinliktedir --- kadın ile aynı yaş aralığında uygulanır. CDC, HPV aşısını erkekler için de yaşa ve bağışıklık durumuna göre önerir; 27-45 yaş aralığında karar bireysel risk ve hekim değerlendirmesiyle verilir. Türkiye&#x27;de erkek aşılaması rutin ulusal takvimde değildir ancak özel uygulanabilir; güncel maliyet kurum ve tarihe göre doğrulanmalıdır.</p><h4>Tarama mevcut mu</h4><p>Erkekte HPV için rutin tarama yoktur. Standart bir Pap-smear erkek versiyonu yok. Yüksek risk grubunda (HIV+, MSM) anal sitoloji ve gerekirse anoskopi düşünülür. Genel popülasyonda klinik bulgu (siğil, kitle) ile başvuru standarttır.</p><h4>Çift yaklaşımı</h4><p>HPV ilişkili tanı sonrası eşin de aşılanması, gerektiğinde muayenesi, açık iletişim premium klinik bakımın parçasıdır. Kadın için tanı, çift için ortak konu olabilir.</p>","visual":false},{"title":"Aşı Sonrası Tarama","preview":"Aşı yüksek riskli tiplerin bir kısmına korur, hepsine değil. Aşılı kadın da yaşa uygun tarama programını sürdürmelidir. İyi haber: aşılı kohortlarda anormal smear ve kolposkopi ihtiyacı belirgin azalıyor.","bodyHtml":"<h4>Yaygın yanlış inanış</h4><p>&quot;Aşı oldum, artık tarama gerekmez.&quot; Yanlış. Aşı (Gardasil-9) dokuz HPV tipini kapsar --- bunlar kanser yapan tiplerin çoğunu içerir ama hepsini değil. Geriye kalan az sayıdaki yüksek riskli tipler hâlâ persistan kalabilir; tarama bu kalan riski yakalar.</p><h4>Aşılı kadın için tarama protokolü</h4><p>Şu an kılavuzlar aşılı ve aşısız kadınlar için aynı tarama aralıklarını öneriyor. Yani:</p><ul><li>21-29 yaş aşılı kadın: 3 yılda bir Pap smear</li><li>30-65 yaş aşılı kadın: 5 yılda bir HPV testi veya ko-test</li></ul><p>Gelecekte aşılı kohortların verisi olgunlaştıkça aşılılarda daha seyrek tarama mümkün olabilir, ancak şu an için kanıt yetersiz.</p><h4>Aşılı kohortlarda gerçek değişim</h4><p>Birleşik Krallık, İskoçya, İsveç verisinde aşılı doğum kohortlarında CIN 3 (yüksek dereceli kanser öncesi) görülme oranı %85+ azalmıştır. Bu, gerçek toplum ölçeğinde aşının kanseri önlediğinin en güçlü kanıtıdır. Türkiye&#x27;de henüz benzer kohort takibi yok ama beklenen yön aynıdır.</p><h4>Aşılı + tarama: gerçek elimine yolu</h4><p>DSÖ 2030 hedefleri (90% aşı, 70% tarama, 90% tedavi) gerçekleştiği takdirde 2120&#x27;de serviks kanseri elimine edilmiş olacak. Bu sadece teknik bir hedef değil --- bireysel kararların toplam etkisinin gücüne dair somut kanıt.</p>","visual":false},{"title":"Sık Sorulan Sorular","preview":"HPV pozitif sonucu sonrası en çok karşılaştığım sorular ve dürüst cevaplar. Bilgi paniği azaltır, eyleme geçirir.","bodyHtml":"<h4>HPV&#x27;m temizlenebilir mi?</h4><p>Çoğu HPV enfeksiyonu (~%90) bağışıklık sistemi tarafından 1-2 yıl içinde temizlenir. Bu pasif değil aktif bir süreçtir --- vücudunuz çalışır. Persistan kalanlar (12+ ay devam eden aynı tip) klinik takip ister.</p><h4>HPV pozitif olmak ilişki problemi mi?</h4><p>Hayır. HPV cinsel olarak aktif çoğu insanın hayatının bir döneminde görülür. Ne sadakat sorgusudur, ne hijyen göstergesi. Yıllarca latent kalabilir --- bugünkü tanı bugünkü bulaş anlamına gelmez.</p><h4>Aşı oldum, eşim olmadı --- bana ne fayda?</h4><p>Aşı sizi virüse maruz kalmadan önce koruyacaktı. Eşinizin de aşılanması cinsel sağlık takımı yaklaşımıdır --- özellikle 26 yaş altıysa öncelikli. 26 üstünde de bireysel değerlendirilebilir.</p><h4>HPV ile bebek doğurabilir miyim?</h4><p>Evet. HPV doğrudan gebelik veya doğumu olumsuz etkilemez. Çok nadir vertikal bulaş laringeal papillomatozis ile ilişkilendirilmiştir; rutin sezaryen endikasyonu değildir.</p><h4>LEEP&#x27;ten sonra gebe kalmam zor mu?</h4><p>Standart bir LEEP ile zorluk beklenmez. Çok geniş konizasyon ya da tekrarlayan LEEP&#x27;ler servikal yetmezlik riski getirebilir; bu yüzden endikasyon önemlidir.</p><h4>Eşim de tarama yaptırabilir mi?</h4><p>Erkekte rutin HPV tarama testi yoktur. Klinik bulgu (siğil, kitle) ile değerlendirilir. HIV+ veya MSM gibi yüksek risk grubunda anal sitoloji düşünülür.</p><h4>Aşı 27 yaşımdan sonra etkili mi?</h4><p>Etkili, ancak fayda kişiseldir. Daha önce karşılaşmadığınız tiplere koruma sağlar. Karşılaşmış olduğunuz tipleri tedavi etmez. 45 yaşına kadar bireysel değerlendirme yapılabilir.</p><h4>Sigara ile ilgisi var mı?</h4><p>Evet. Sigara HPV temizlenmesini geciktirir, persistan enfeksiyon riskini ve servikal displazi gelişme riskini artırır. Sigarayı bırakmak kanıta dayalı en güçlü destek müdahalelerden biridir.</p>","visual":false}];

