function renderHpvKnowledge(language = activeLanguage) {
  const container = document.querySelector('[data-hpv-knowledge]');
  if (!container) return;
  const data = hpvKnowledgeTranslations[language] || hpvKnowledgeTranslations.en || hpvKnowledgeTranslations.tr;
  const labels = hpvReaderLabels[language] || hpvReaderLabels.en || hpvReaderLabels.tr;
  const cards = language === 'tr' && hpvDocxTrCards.length ? hpvDocxTrCards : data.cards;
  const activeIndex = Number.isInteger(activeHpvArticleIndex) && activeHpvArticleIndex >= 0 && activeHpvArticleIndex < cards.length
    ? activeHpvArticleIndex
    : null;
  const renderBody = (card) => {
    if (card.bodyHtml) return card.bodyHtml;
    return (card.body || []).map((paragraph) => `<p>${escapeHtml(paragraph)}</p>`).join('');
  };
  const renderGem = (index) => {
    const gems = [
      { slug: 'diamond', light: '#ffffff', mid: '#d7eef8', deep: '#5b7488', edge: '#f7fdff' },
      { slug: 'ruby', light: '#fff3f7', mid: '#d83f71', deep: '#3d071b', edge: '#ffc0d2' },
      { slug: 'emerald', light: '#effff7', mid: '#25a56d', deep: '#073b2a', edge: '#b8f0d2' },
      { slug: 'sapphire', light: '#f1f7ff', mid: '#2b67c7', deep: '#071f54', edge: '#abc9ff' },
      { slug: 'amethyst', light: '#fbf2ff', mid: '#8a4fc7', deep: '#351247', edge: '#e7c6ff' },
      { slug: 'topaz', light: '#fff8e2', mid: '#df9f32', deep: '#5b3208', edge: '#ffe2a0' },
      { slug: 'aquamarine', light: '#f0fffd', mid: '#4cc5c4', deep: '#0a4c55', edge: '#c5fbf7' },
      { slug: 'garnet', light: '#fff1f1', mid: '#9d1f3b', deep: '#33070f', edge: '#f1a5b0' },
      { slug: 'opal', light: '#fffdf8', mid: '#cfd8e8', deep: '#6f7890', edge: '#f4cce8' },
      { slug: 'citrine', light: '#fff9de', mid: '#e6c24a', deep: '#6d4b08', edge: '#fff0a8' },
    ];
    const gem = gems[index % gems.length];
    const gradA = `hpvGemA${index}`;
    const gradB = `hpvGemB${index}`;
    return `
      <span class="hpv-gem hpv-gem-${gem.slug}" aria-hidden="true">
        <svg viewBox="0 0 120 120" focusable="false">
          <defs>
            <radialGradient id="${gradA}" cx="32%" cy="18%" r="70%">
              <stop offset="0" stop-color="${gem.light}"/>
              <stop offset=".24" stop-color="${gem.edge}"/>
              <stop offset=".55" stop-color="${gem.mid}"/>
              <stop offset="1" stop-color="${gem.deep}"/>
            </radialGradient>
            <linearGradient id="${gradB}" x1="12" y1="10" x2="108" y2="110" gradientUnits="userSpaceOnUse">
              <stop offset="0" stop-color="${gem.light}"/>
              <stop offset=".32" stop-color="${gem.mid}"/>
              <stop offset="1" stop-color="${gem.deep}"/>
            </linearGradient>
          </defs>
          <path d="M28 24 L44 14 H76 L94 25 L106 51 L60 108 L14 52 Z" fill="url(#${gradB})"/>
          <path d="M28 24 L44 14 L40 49 L14 52 Z" fill="${gem.mid}" opacity=".78"/>
          <path d="M44 14 H76 L60 49 L40 49 Z" fill="${gem.edge}" opacity=".72"/>
          <path d="M76 14 L94 25 L80 49 L60 49 Z" fill="${gem.mid}" opacity=".86"/>
          <path d="M14 52 L40 49 L60 108 Z" fill="${gem.deep}" opacity=".82"/>
          <path d="M40 49 H60 L60 108 Z" fill="url(#${gradA})" opacity=".92"/>
          <path d="M60 49 H80 L60 108 Z" fill="${gem.mid}" opacity=".76"/>
          <path d="M80 49 L106 51 L60 108 Z" fill="${gem.deep}" opacity=".88"/>
          <path d="M25 30 C38 19 58 18 76 22" fill="none" stroke="#fff" stroke-width="5" stroke-linecap="round" opacity=".55"/>
          <path d="M18 52 H104 M28 24 L40 49 L60 25 L80 49 L94 25 M44 14 L60 49 L76 14 M40 49 L60 108 L80 49" fill="none" stroke="rgba(255,255,255,.34)" stroke-width="1.8"/>
          <path d="M28 24 L44 14 H76 L94 25 L106 51 L60 108 L14 52 Z" fill="none" stroke="rgba(7,28,52,.28)" stroke-width="2"/>
        </svg>
      </span>
    `;
	  };
  const renderHpvCardVisual = (card, index) => {
    const visual = pickKeywordCardVisual({ ...card, categoryKey: 'hpv', slug: `hpv-${index}` }, 'hpv', index);
    if (!visual?.src) return renderGem(index);
    return `
      <span class="hpv-card-visual" aria-hidden="true">
        <img src="${escapeHtml(visual.src)}" alt="${escapeHtml(visual.alt || card.title || '')}" loading="lazy" decoding="async" onerror="this.parentElement?.remove()" />
        ${renderGem(index)}
      </span>
    `;
  };
		  if (activeIndex !== null) {
    const card = cards[activeIndex];
    const number = String(activeIndex + 1).padStart(2, '0');
    const previousMenuLabel = getPreviousMenuLabel(language);
    container.innerHTML = `
      <article class="hpv-reader-page${card.visual ? ' has-visual' : ''}" id="hpv-article-${number}" aria-live="polite">
        <div class="hpv-reader-topline">
          <button class="hpv-reader-back" type="button" data-hpv-back>← ${escapeHtml(previousMenuLabel)}</button>
          ${renderGem(activeIndex)}
        </div>
        <h2>${escapeHtml(card.title)}</h2>
        <p class="hpv-reader-preview">${escapeHtml(card.preview)}</p>
        ${card.visual ? '<div class="hpv-article-visual hpv-reader-visual" aria-hidden="true"></div>' : ''}
        <div class="hpv-reader-body">${renderBody(card)}</div>
      </article>
    `;
    container.querySelectorAll('[data-hpv-back]').forEach((button) => {
      button.addEventListener('click', () => {
        activeHpvArticleIndex = null;
        const url = new URL(window.location.href);
        url.hash = 'sayfa-hpv';
        window.history.pushState({}, '', `${url.pathname}${url.search}${url.hash}`);
        renderHpvKnowledge(language);
        activatePage('hpv', { updateHash: false, instant: true });
      });
    });
    return;
  }
  container.innerHTML = `
    <div class="hpv-knowledge-hero">
      <div>
        <p class="hpv-kicker">${escapeHtml(data.label)}</p>
        <h2>${escapeHtml(data.title)}</h2>
        <span class="hpv-subtitle">${escapeHtml(data.subtitle)}</span>
        <strong class="hpv-emphasis">${escapeHtml(data.emphasis)}</strong>
        <p class="hpv-hero-text">${escapeHtml(data.intro)}</p>
      </div>
      <div class="hpv-hero-visual" aria-hidden="true"></div>
    </div>
    <div class="hpv-letter">
      ${data.letter.map((paragraph) => `<p>${escapeHtml(paragraph)}</p>`).join('')}
    </div>
	    <div class="hpv-card-grid" aria-label="${escapeHtml(data.title)} bilgi kartları">
	      ${cards.map((card, index) => `
	        <button class="hpv-card" type="button" data-hpv-open-index="${index}" aria-label="${escapeHtml(card.title)} ${escapeHtml(labels.cardAria)}">
	          ${renderHpvCardVisual(card, index)}
	          <h3>${escapeHtml(card.title)}</h3>
	          <p>${escapeHtml(card.preview)}</p>
	          <em>${escapeHtml(labels.open)}</em>
        </button>
      `).join('')}
    </div>
    <section class="hpv-academic" aria-label="${escapeHtml(data.academicTitle)}">
      <h3>${escapeHtml(data.academicTitle)}</h3>
      <ul>${data.academic.map((item) => `<li>${escapeHtml(item)}</li>`).join('')}</ul>
    </section>
    <section class="hpv-sources" aria-label="${escapeHtml(data.sourcesTitle)}">
      <p class="hpv-source-title">${escapeHtml(data.sourcesTitle)}</p>
      <ul>${hpvSourceLinks.map((source) => `<li><a href="${escapeHtml(source.url)}" target="_blank" rel="noopener">${escapeHtml(source.label)}</a></li>`).join('')}</ul>
    </section>
    <section class="hpv-cta-panel">
      <h3>${escapeHtml(data.ctaTitle)}</h3>
      <p>${escapeHtml(data.ctaText)}</p>
      <div class="hpv-cta-actions">
        <a class="button button-primary" href="https://www.livhospital.com/dr-ogr-uyesi-serhat-sen" target="_blank" rel="noopener">${escapeHtml(data.ctaPrimary)}</a>
        <a class="button button-secondary" href="#jinekologum">${escapeHtml(data.ctaSecondary)}</a>
      </div>
    </section>
  `;
  container.querySelectorAll('[data-hpv-open-index]').forEach((button) => {
    button.addEventListener('click', () => {
      const index = Number.parseInt(button.dataset.hpvOpenIndex || '0', 10);
      activeHpvArticleIndex = Number.isFinite(index) ? index : 0;
      const url = new URL(window.location.href);
      url.hash = `hpv-article-${String(activeHpvArticleIndex + 1).padStart(2, '0')}`;
      window.history.pushState({}, '', `${url.pathname}${url.search}${url.hash}`);
      renderHpvKnowledge(language);
      container.scrollIntoView({ behavior: 'smooth', block: 'start' });
    });
  });
  container.querySelectorAll('a[href^="#"]').forEach((link) => {
    normalizeInternalLink(link);
    link.addEventListener('click', (event) => {
      const route = getRouteFromHash(link.getAttribute('href') || '');
      event.preventDefault();
      activatePage(route);
    });
  });
}

