function getGuideVisual(item = {}) {
  if (item.visual && item.visual.src) return item.visual;
  if (item.categoryKey === 'saglikli-hamilelik' && item.subNumber) {
    return pregnancyGuideVisuals[item.subNumber] || null;
  }
  const fallback = item.categoryKey === 'genital-performans'
    ? 'genital'
    : item.categoryKey === 'saglikli-hamilelik'
      ? 'pregnancy'
      : 'medical';
  return pickKeywordCardVisual(item, fallback, numericVisualSeed(item));
}

function guideVisualMarkup(item, className = 'guide-card-visual') {
  const visual = getGuideVisual(item);
  if (!visual?.src) return '';
  const alt = visual.alt || `${item.title || ''} için anonim gerçek fotoğraf`;
  return `
    <span class="${escapeHtml(className)}">
      <img src="${escapeHtml(visual.src)}" alt="${escapeHtml(alt)}" loading="lazy" decoding="async" onerror="this.parentElement?.remove()" />
    </span>
  `;
}

function guideCardMarkup(item) {
  const cta = getCardContinuationLabel(activeLanguage);
  const ariaSuffix = item.ariaSuffix || guideLanguageLabels.tr.ariaSuffix;
  const hasVisual = Boolean(getGuideVisual(item));
  return `
    <button class="guide-card${hasVisual ? ' guide-card-has-visual' : ''}" type="button" data-guide-slug="${escapeHtml(item.slug)}" aria-label="${escapeHtml(item.title)} ${escapeHtml(ariaSuffix)}">
      ${guideVisualMarkup(item)}
      <h3>${escapeHtml(item.title)}</h3>
      <p>${escapeHtml(item.description)}</p>
      <em>${escapeHtml(cta)}</em>
    </button>
  `;
}

function guideGroupCardMarkup(group) {
  const cta = getCardContinuationLabel(activeLanguage);
  const visual = getGuideVisual(group);
  return `
    <button class="guide-card guide-main-card${visual ? ' guide-card-has-visual' : ''}" type="button" data-guide-group="${escapeHtml(group.slug)}" aria-label="${escapeHtml(group.title)}">
      ${guideVisualMarkup(group, 'guide-card-visual guide-main-visual')}
      <h3>${escapeHtml(group.title)}</h3>
      <p>${escapeHtml(group.description)}</p>
      <em>${escapeHtml(cta)}</em>
    </button>
  `;
}

function getGuideBackLabel(language = activeLanguage) {
  return getPreviousMenuLabel(language);
}

const genitalPerformanceDataUrls = {
  tr: 'assets/genital-performance/genital-performance.tr.json',
  en: 'assets/genital-performance/genital-performance.en.json',
  it: 'assets/genital-performance/genital-performance.it.json',
  de: 'assets/genital-performance/genital-performance.de.json',
  fr: 'assets/genital-performance/genital-performance.fr.json',
  ar: 'assets/genital-performance/genital-performance.ar.json',
  ru: 'assets/genital-performance/genital-performance.ru.json',
};

const genitalPerformanceCache = {};
const genitalPerformancePromises = {};
let activeGenitalPerformanceMainKey = null;
let activeGenitalPerformanceCardSlug = null;

function getGenitalPerformanceUrl(language = activeLanguage) {
  return genitalPerformanceDataUrls[language] || genitalPerformanceDataUrls.tr;
}

async function loadGenitalPerformanceData(language = activeLanguage) {
  const cacheKey = genitalPerformanceDataUrls[language] ? language : 'tr';
  if (genitalPerformanceCache[cacheKey]) return genitalPerformanceCache[cacheKey];
  if (!genitalPerformancePromises[cacheKey]) {
    genitalPerformancePromises[cacheKey] = fetch(getGenitalPerformanceUrl(cacheKey))
      .then((response) => {
        if (!response.ok) throw new Error(`genital-performance-${cacheKey}-${response.status}`);
        return response.json();
      })
      .catch(async () => {
        if (cacheKey === 'tr') throw new Error('genital-performance-tr-missing');
        const fallback = await loadGenitalPerformanceData('tr');
        return {
          ...fallback,
          language: cacheKey,
          isFallback: true,
        };
      })
      .then((data) => {
        genitalPerformanceCache[cacheKey] = data;
        return data;
      });
  }
  return genitalPerformancePromises[cacheKey];
}

function genitalPerformanceSummaryText(parts = []) {
  return Array.isArray(parts) ? parts.filter(Boolean).join(' ') : String(parts || '');
}

function renderGenitalPerformanceStillLife(theme = '') {
  const normalized = String(theme || '').toLowerCase();
  const petal = normalized.includes('rose') ? 'gp-petal-wine' : normalized.includes('sage') ? 'gp-petal-sage' : 'gp-petal-camel';
  return `
    <span class="gp-still-life" aria-hidden="true">
      <span class="gp-silk"></span>
      <span class="gp-orb ${petal}"></span>
      <span class="gp-orb gp-orb-soft"></span>
      <span class="gp-stem"></span>
    </span>
  `;
}

function genitalPerformanceCardVisual(item = {}, className = 'gp-card-visual') {
  const visualSeed = {
    categoryKey: 'genital-performans',
    key: item.key,
    slug: item.slug,
    number: item.number,
    title: item.title,
    subtitle: item.subtitle,
    summary: item.summary,
    visualTheme: item.visualTheme,
  };
  const visual = pickKeywordCardVisual(visualSeed, 'genital', numericVisualSeed(visualSeed) - 1);
  return cardVisualMarkup(visual, className);
}

function genitalPerformanceMainMarkup(item, section) {
  const summary = genitalPerformanceSummaryText(item.summary);
  return `
    <button class="gp-main-card" type="button" data-gp-main="${escapeHtml(item.key)}">
      ${genitalPerformanceCardVisual(item, 'gp-card-visual gp-main-visual')}
      <span class="gp-main-number">${String(item.number).padStart(2, '0')}</span>
      <h3>${escapeHtml(item.title)}</h3>
      <p>${escapeHtml(item.subtitle || summary)}</p>
      <em>${escapeHtml(section.continue || getCardContinuationLabel(activeLanguage))}</em>
    </button>
  `;
}

function genitalPerformanceSubcardMarkup(item, section) {
  return `
    <button class="gp-sub-card" type="button" data-gp-card="${escapeHtml(item.slug)}">
      ${genitalPerformanceCardVisual(item, 'gp-card-visual gp-sub-visual')}
      <span class="gp-sub-copy">
        <span class="gp-sub-number">${escapeHtml(item.number)}</span>
        <h4>${escapeHtml(item.title)}</h4>
        <p>${escapeHtml(item.summary)}</p>
        <em>${escapeHtml(section.continue || getCardContinuationLabel(activeLanguage))}</em>
      </span>
    </button>
  `;
}

function renderGenitalPerformanceArticle(container, data, mainCard, item) {
  const section = data.section || {};
  const previousMenuLabel = getPreviousMenuLabel(activeLanguage);
  const body = Array.isArray(item.body) ? item.body : [];
  const color = mainCard.colors || {};
  container.style.setProperty('--gp-bg', color.bg || '#F5F0E8');
  container.style.setProperty('--gp-surface', color.surface || '#FFF9F2');
  container.style.setProperty('--gp-accent', color.accent || '#B8956A');
  container.style.setProperty('--gp-watermark', color.watermark || '#E0C7A7');
  container.innerHTML = `
    <article class="gp-article">
      <div class="gp-reader-controls">
        <button type="button" class="gp-back" data-gp-back-sub>${escapeHtml(previousMenuLabel)}</button>
      </div>
      <div class="gp-article-shell">
        <aside class="gp-article-visual">
          ${renderGenitalPerformanceStillLife(mainCard.visualTheme)}
          <span>${escapeHtml(mainCard.title)}</span>
        </aside>
        <div class="gp-article-copy">
          <p class="gp-kicker">${escapeHtml(mainCard.title)} · ${escapeHtml(section.readTime || '')}</p>
          <h3>${escapeHtml(item.title)}</h3>
          <p class="gp-lede">${escapeHtml(item.summary)}</p>
          ${body.map((paragraph) => `<p>${escapeHtml(paragraph)}</p>`).join('')}
          ${item.doctorNote ? `<blockquote><strong>${escapeHtml(section.doctorNoteLabel || 'Dr. notu')}</strong>${escapeHtml(item.doctorNote.replace(/^Dr\. notu\s*—?\s*/i, ''))}</blockquote>` : ''}
        </div>
      </div>
    </article>
  `;
  container.querySelector('[data-gp-back-sub]')?.addEventListener('click', () => {
    activeGenitalPerformanceCardSlug = null;
    renderGenitalPerformanceExplorer(activeLanguage);
  });
}

function renderGenitalPerformanceSubcards(container, data, mainCard) {
  const section = data.section || {};
  const previousMenuLabel = getPreviousMenuLabel(activeLanguage);
  const color = mainCard.colors || {};
  container.style.setProperty('--gp-bg', color.bg || '#F5F0E8');
  container.style.setProperty('--gp-surface', color.surface || '#FFF9F2');
  container.style.setProperty('--gp-accent', color.accent || '#B8956A');
  container.style.setProperty('--gp-watermark', color.watermark || '#E0C7A7');
  container.innerHTML = `
    <section class="gp-layer gp-layer-subcards">
      <div class="gp-layer-heading">
        <button type="button" class="gp-back" data-gp-back-main>${escapeHtml(previousMenuLabel)}</button>
        <p class="gp-kicker">${escapeHtml(section.kicker || 'Genital Performans')}</p>
        <h3>${escapeHtml(mainCard.title)}</h3>
        <p>${escapeHtml(genitalPerformanceSummaryText(mainCard.approach) || mainCard.subtitle || '')}</p>
      </div>
      <div class="gp-sub-grid">
        ${(mainCard.cards || []).map((item) => genitalPerformanceSubcardMarkup(item, section)).join('')}
      </div>
    </section>
  `;
  container.querySelector('[data-gp-back-main]')?.addEventListener('click', () => {
    activeGenitalPerformanceMainKey = null;
    activeGenitalPerformanceCardSlug = null;
    renderGenitalPerformanceExplorer(activeLanguage);
  });
  container.querySelectorAll('[data-gp-card]').forEach((button) => {
    button.addEventListener('click', () => {
      activeGenitalPerformanceCardSlug = button.dataset.gpCard || null;
      renderGenitalPerformanceExplorer(activeLanguage);
    });
  });
}

async function renderGenitalPerformanceExplorer(language = activeLanguage) {
  const container = document.querySelector('[data-genital-performance-explorer]');
  if (!container) return;
  try {
    if (!container.dataset.ready) {
      container.innerHTML = `<div class="gp-loading">${escapeHtml(translations[language]?.healthyContentUi?.loading || translations.tr.healthyContentUi.loading)}</div>`;
    }
    const data = await loadGenitalPerformanceData(language);
    const section = data.section || {};
    if (!activeGenitalPerformanceMainKey && data.mainCards?.[0]?.key) {
      activeGenitalPerformanceMainKey = null;
    }
    const mainCards = Array.isArray(data.mainCards) ? data.mainCards : [];
    const activeMain = mainCards.find((item) => item.key === activeGenitalPerformanceMainKey);
    const activeArticle = activeMain?.cards?.find((item) => item.slug === activeGenitalPerformanceCardSlug);
    container.dataset.ready = 'true';
    if (activeMain && activeArticle) {
      renderGenitalPerformanceArticle(container, data, activeMain, activeArticle);
      container.scrollIntoView({ behavior: 'smooth', block: 'start' });
      return;
    }
    if (activeMain) {
      renderGenitalPerformanceSubcards(container, data, activeMain);
      container.scrollIntoView({ behavior: 'smooth', block: 'start' });
      return;
    }
    const firstColors = mainCards[0]?.colors || {};
    container.style.setProperty('--gp-bg', firstColors.bg || '#F5F0E8');
    container.style.setProperty('--gp-surface', firstColors.surface || '#FFF9F2');
    container.style.setProperty('--gp-accent', firstColors.accent || '#B8956A');
    container.style.setProperty('--gp-watermark', firstColors.watermark || '#E0C7A7');
    container.innerHTML = `
      <section class="gp-layer gp-layer-main">
        <div class="gp-layer-heading">
          <p class="gp-kicker">${escapeHtml(section.kicker || 'Genital Performans')}</p>
          <h3>${escapeHtml(section.title || 'Genital Performans')}</h3>
          <p>${escapeHtml(section.lede || '')}</p>
        </div>
        <div class="gp-main-grid">
          ${mainCards.map((item) => genitalPerformanceMainMarkup(item, section)).join('')}
        </div>
      </section>
    `;
    container.querySelectorAll('[data-gp-main]').forEach((button) => {
      button.addEventListener('click', () => {
        activeGenitalPerformanceMainKey = button.dataset.gpMain || null;
        activeGenitalPerformanceCardSlug = null;
        renderGenitalPerformanceExplorer(activeLanguage);
      });
    });
  } catch (error) {
    container.innerHTML = `<div class="gp-loading is-error">${escapeHtml(translations[language]?.healthyContentUi?.error || translations.tr.healthyContentUi.error)}</div>`;
  }
}

