function setPortalMode(mode = portalMemberSession ? 'member' : 'login') {
  const shell = document.querySelector('.patient-portal-shell');
	  const authCard = document.querySelector('[data-portal-auth-card]');
	  const loginForm = document.querySelector('[data-patient-login-form]');
	  const resetForm = document.querySelector('[data-password-reset-form]');
	  const registerForm = document.querySelector('[data-patient-intake-form]');
  const memberArea = document.querySelector('[data-portal-member-area]');
  const memberPanels = document.querySelector('[data-portal-member-panels]');
  const adminArea = document.querySelector('[data-portal-admin-area]');
  const adminPanels = document.querySelector('[data-portal-admin-panels]');
  const success = document.querySelector('[data-registration-success]');
  const loginStatus = document.querySelector('[data-login-status]');
  const portalStatus = document.querySelector('[data-portal-status]');
	  const nextMode = mode === 'register' || mode === 'member' || mode === 'admin' || mode === 'reset' ? mode : 'login';
  if (shell) {
    shell.dataset.portalMode = nextMode;
	    shell.classList.toggle('is-login-flow', nextMode === 'login');
	    shell.classList.toggle('is-register-flow', nextMode === 'register');
	    shell.classList.toggle('is-reset-flow', nextMode === 'reset');
	    shell.classList.toggle('is-member-session', nextMode === 'member');
    shell.classList.toggle('is-admin-session', nextMode === 'admin');
  }
	  if (authCard) authCard.hidden = nextMode === 'member' || nextMode === 'admin';
	  if (loginForm) loginForm.hidden = nextMode !== 'login';
	  if (resetForm) resetForm.hidden = nextMode !== 'reset';
	  if (registerForm) registerForm.hidden = nextMode !== 'register';
  if (memberArea) memberArea.hidden = nextMode !== 'member';
  if (memberPanels) memberPanels.hidden = nextMode !== 'member';
  if (adminArea) adminArea.hidden = nextMode !== 'admin';
  if (adminPanels) adminPanels.hidden = nextMode !== 'admin';
	  if (success && nextMode !== 'register') success.hidden = true;
	  if (loginStatus && nextMode !== 'login') loginStatus.textContent = '';
	  const resetStatus = document.querySelector('[data-reset-status]');
	  if (resetStatus && nextMode !== 'reset') resetStatus.textContent = '';
  if (portalStatus && nextMode !== 'register') portalStatus.textContent = '';
  if (nextMode === 'member') activatePortalPanel('questions', { updateHash: false, scroll: false });
  if (nextMode === 'admin') activateAdminPanel('requests');
  updatePortalModeText(nextMode);
}

function isLikelyPortalAdmin(username) {
  const normalized = String(username || '').trim().toLowerCase().replace(/\s+/g, '');
  return normalized === 'serhat@drserhatsen.com' || normalized === 'serhat@drserhat' || normalized.includes('@drserhatsen.com');
}

