const callbackForm = document.querySelector('.callback-form');
const formNote = document.querySelector('[data-form-note]');
const fullCvToggleButton = document.querySelector('[data-toggle-full-cv]');
const fullCvPanel = document.querySelector('[data-full-cv-panel]');

function openFullCvPanel() {
  if (!fullCvToggleButton || !fullCvPanel) return;
  fullCvPanel.hidden = false;
  fullCvToggleButton.setAttribute('aria-expanded', 'true');
  fullCvPanel.scrollIntoView({ block: 'start', behavior: 'smooth' });
}

fullCvToggleButton?.addEventListener('click', openFullCvPanel);

if (callbackForm) {
  callbackForm.addEventListener('submit', async (event) => {
    event.preventDefault();
    const data = new FormData(callbackForm);
    const name = String(data.get('name') || '').trim();
    const email = String(data.get('email') || '').trim();
    const phone = String(data.get('phone') || '').trim();
    const message = String(data.get('message') || '').trim();
    const channel = String(data.get('channel') || 'whatsapp');
    const t = translations[activeLanguage] || translations.tr;
    const channelLabels = {
      whatsapp: t.formMessages.channelWhatsapp || translations.tr.formMessages.channelWhatsapp,
      email: t.formMessages.channelEmail || translations.tr.formMessages.channelEmail,
      phone: t.formMessages.channelPhone || translations.tr.formMessages.channelPhone,
    };
    const channelLabel = channelLabels[channel] || channel;
    const whatsappDigits = phone.replace(/\D/g, '');
    const whatsappReplyUrl = whatsappDigits ? `https://wa.me/${whatsappDigits}` : '';
    const subject =
      channel === 'whatsapp'
        ? t.formMessages.subjectWhatsapp || t.formMessages.subject
        : channel === 'phone'
          ? t.formMessages.subjectPhone || t.formMessages.subject
          : t.formMessages.subject;

    if (!phone) {
      const requiredMessage = t.formMessages.phoneRequired || translations.tr.formMessages.phoneRequired;
      formNote?.classList.remove('is-success');
      formNote?.classList.add('is-error');
      if (formNote) formNote.textContent = requiredMessage;
      callbackForm.querySelector('[name="phone"]')?.focus();
      return;
    }

    const body = [
      subject,
      `${t.formMessages.name}: ${name}`,
      `${t.formMessages.email}: ${email}`,
      `${t.formMessages.phone}: ${phone}`,
      `${t.formMessages.channel}: ${channelLabel}`,
      ...(whatsappReplyUrl ? [`WhatsApp yanıt bağlantısı: ${whatsappReplyUrl}`] : []),
      '',
      `${t.formMessages.message}: ${message}`,
    ].join('\n');

    const successMessage = t.formMessages.success || translations.tr.formMessages.success;
    const sendingMessage = t.formMessages.sending || translations.tr.formMessages.sending;
    const errorMessage = t.formMessages.error || translations.tr.formMessages.error;
    const deliveryEndpoint = callbackForm.dataset.deliveryEndpoint;

    callbackForm.classList.add('is-sending');
    callbackForm.querySelector('button[type="submit"]')?.setAttribute('disabled', 'disabled');
    if (formNote) {
      formNote.classList.remove('is-success', 'is-error');
      formNote.textContent = sendingMessage;
    }

    const payload = new FormData();
    payload.append('_subject', subject);
    payload.append('_template', 'box');
    payload.append('_captcha', 'false');
    payload.append('Ad Soyad', String(name));
    payload.append('E-posta', String(email));
    payload.append('WhatsApp / Telefon', String(phone));
    if (whatsappReplyUrl) payload.append('Hastaya WhatsApp ile dönüş bağlantısı', whatsappReplyUrl);
    payload.append('Tercih edilen yanıt kanalı', channelLabel);
    payload.append('Talep türü', subject);
    payload.append('Mesaj', String(message));
    payload.append('Sayfa', window.location.href);
    payload.append('Not', body);

    try {
      if (!deliveryEndpoint) throw new Error('delivery-endpoint-missing');
      const response = await fetch(deliveryEndpoint, {
        method: 'POST',
        headers: { Accept: 'application/json' },
        body: payload,
      });
      if (!response.ok) throw new Error(`delivery-failed-${response.status}`);
      if (formNote) {
        formNote.classList.add('is-success');
        formNote.textContent = successMessage;
      }
      callbackForm.reset();
      return;
    } catch (error) {
      navigator.clipboard?.writeText(body).catch(() => {});
      if (formNote) {
        formNote.classList.add('is-error');
        formNote.textContent = errorMessage;
      }
      window.location.href = `mailto:serhatsen8@gmail.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    } finally {
      callbackForm.classList.remove('is-sending');
      callbackForm.querySelector('button[type="submit"]')?.removeAttribute('disabled');
    }
  });
}

