if (storyForm) {
  storyForm.addEventListener('submit', async (event) => {
    event.preventDefault();
    const data = new FormData(storyForm);
    const name = String(data.get('name') || '').trim();
    const email = String(data.get('email') || '').trim();
    const message = String(data.get('message') || '').trim();
    const consent = data.get('consent') === 'yes';
    const t = translations[activeLanguage] || translations.tr;
    const sm = t.storyMessages || translations.tr.storyMessages;
    const subject = sm.subject;

    if (!message) {
      const requiredMessage = sm.messageRequired || translations.tr.storyMessages.messageRequired;
      storyNote?.classList.remove('is-success');
      storyNote?.classList.add('is-error');
      if (storyNote) storyNote.textContent = requiredMessage;
      storyForm.querySelector('[name="message"]')?.focus();
      return;
    }
    if (!consent) {
      const requiredMessage = sm.consentRequired || translations.tr.storyMessages.consentRequired;
      storyNote?.classList.remove('is-success');
      storyNote?.classList.add('is-error');
      if (storyNote) storyNote.textContent = requiredMessage;
      storyForm.querySelector('[name="consent"]')?.focus();
      return;
    }

    const body = [
      sm.header || subject,
      `${sm.name}: ${name || '-'}`,
      `${sm.email}: ${email || '-'}`,
      `${sm.consent}: ${sm.consentYes}`,
      '',
      `${sm.message}:`,
      message,
      '',
      `Sayfa / Page: ${window.location.href}`,
    ].join('\n');

    const successMessage = sm.success || translations.tr.storyMessages.success;
    const sendingMessage = sm.sending || translations.tr.storyMessages.sending;
    const errorMessage = sm.error || translations.tr.storyMessages.error;
    const deliveryEndpoint = storyForm.dataset.deliveryEndpoint;

    storyForm.classList.add('is-sending');
    storyForm.querySelector('button[type="submit"]')?.setAttribute('disabled', 'disabled');
    if (storyNote) {
      storyNote.classList.remove('is-success', 'is-error');
      storyNote.textContent = sendingMessage;
    }

    const payload = new FormData();
    payload.append('_subject', subject);
    payload.append('_template', 'box');
    payload.append('_captcha', 'false');
    payload.append('_form_type', 'story');
    payload.append(sm.name || 'Name', name || '-');
    payload.append(sm.email || 'Email', email || '-');
    payload.append(sm.consent || 'Consent', sm.consentYes || 'Yes');
    payload.append(sm.message || 'Message', message);
    payload.append('Sayfa', window.location.href);
    payload.append('Not', body);

    try {
      if (!deliveryEndpoint) throw new Error('delivery-endpoint-missing');
      const response = await fetch(deliveryEndpoint, {
        method: 'POST',
        headers: { Accept: 'application/json' },
        body: payload,
      });
      if (!response.ok) throw new Error(`delivery-failed-${response.status}`);
      if (storyNote) {
        storyNote.classList.add('is-success');
        storyNote.textContent = successMessage;
      }
      storyForm.reset();
      return;
    } catch (error) {
      navigator.clipboard?.writeText(body).catch(() => {});
      if (storyNote) {
        storyNote.classList.add('is-error');
        storyNote.textContent = errorMessage;
      }
      window.location.href = `mailto:serhatsen8@gmail.com?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
    } finally {
      storyForm.classList.remove('is-sending');
      storyForm.querySelector('button[type="submit"]')?.removeAttribute('disabled');
    }
  });
}

const ANALYTICS_CONSENT_COOKIE = 'serhat_analytics_consent';
const ANALYTICS_CONSENT_MAX_AGE = 60 * 60 * 24 * 180;
const cookieConsentPanel = document.querySelector('[data-cookie-consent]');
const cookieAcceptButton = document.querySelector('[data-cookie-accept]');
const cookieRejectButton = document.querySelector('[data-cookie-reject]');
let volatileAnalyticsConsent = null;

function getCookieValue(name) {
  try {
    return document.cookie
      .split(';')
      .map((item) => item.trim())
      .find((item) => item.startsWith(`${name}=`))
      ?.split('=')
      .slice(1)
      .join('=');
  } catch (error) {
    return null;
  }
}

function readAnalyticsConsent() {
  const cookieValue = getCookieValue(ANALYTICS_CONSENT_COOKIE);
  if (cookieValue === 'accepted' || cookieValue === 'rejected') return cookieValue;
  return volatileAnalyticsConsent;
}

function writeAnalyticsConsent(value) {
  volatileAnalyticsConsent = value;
  window.serhatAnalyticsConsent = value;
  try {
    document.cookie = `${ANALYTICS_CONSENT_COOKIE}=${value}; max-age=${ANALYTICS_CONSENT_MAX_AGE}; path=/; SameSite=Lax`;
  } catch (error) {
    // Some sandboxed previews can block cookie writes. The in-memory value above keeps this visit stable.
  }
}

function enableAnalytics() {
  if (window.serhatAnalyticsEnabled) return;
  window.serhatAnalyticsEnabled = true;
  // Ölçüm kimliği eklendiğinde istatistik kodu buraya bağlanacak.
  window.dispatchEvent(new CustomEvent('serhat:analytics-consent', { detail: { consent: 'accepted' } }));
}

function applyAnalyticsConsent(consent) {
  window.serhatAnalyticsConsent = consent || null;
  if (consent === 'accepted') {
    if (cookieConsentPanel) cookieConsentPanel.hidden = true;
    enableAnalytics();
    return;
  }
  if (consent === 'rejected') {
    if (cookieConsentPanel) cookieConsentPanel.hidden = true;
    return;
  }
  if (cookieConsentPanel) cookieConsentPanel.hidden = false;
}

cookieAcceptButton?.addEventListener('click', () => {
  writeAnalyticsConsent('accepted');
  applyAnalyticsConsent('accepted');
});

cookieRejectButton?.addEventListener('click', () => {
  writeAnalyticsConsent('rejected');
  applyAnalyticsConsent('rejected');
});

applyAnalyticsConsent(readAnalyticsConsent());

const compactHeaderMedia = window.matchMedia('(max-width: 560px)');
let mobileRailManualOverride = null;

function updateCompactHeader() {
  const shouldCompact = compactHeaderMedia.matches && window.scrollY > 48;
  document.body.classList.toggle('is-header-compact', shouldCompact);
  if (compactHeaderMedia.matches) {
    const shouldHideRail = window.scrollY > Math.max(72, window.innerHeight * 0.18);
    if (mobileRailManualOverride === null || shouldHideRail) {
      setMobileRailHidden(shouldHideRail);
      if (!shouldHideRail) {
        mobileRailManualOverride = null;
      }
    }
  }
}

if (siteHeader) {
  updateCompactHeader();
  window.addEventListener('scroll', () => window.requestAnimationFrame(updateCompactHeader), { passive: true });
  compactHeaderMedia.addEventListener?.('change', updateCompactHeader);
}

let mobileRailGesture = null;

function setMobileRailHidden(hidden) {
  if (!compactHeaderMedia.matches) {
    document.body.classList.remove('is-mobile-rail-hidden');
    mobileRailManualOverride = null;
    return;
  }
  document.body.classList.toggle('is-mobile-rail-hidden', Boolean(hidden));
}

function updateMobileRailMode() {
  if (!compactHeaderMedia.matches) {
    document.body.classList.remove('is-mobile-rail-hidden');
    mobileRailManualOverride = null;
  }
}

function startMobileRailGesture(x, y, target) {
  if (!compactHeaderMedia.matches) return;
  if (target?.closest?.('input, textarea, select, [contenteditable="true"]')) return;
  mobileRailGesture = { x, y, time: Date.now() };
}

function finishMobileRailGesture(x, y) {
  if (!mobileRailGesture || !compactHeaderMedia.matches) {
    mobileRailGesture = null;
    return;
  }
  const deltaX = x - mobileRailGesture.x;
  const deltaY = y - mobileRailGesture.y;
  const elapsed = Date.now() - mobileRailGesture.time;
  mobileRailGesture = null;
  if (elapsed > 950 || Math.abs(deltaX) < 46 || Math.abs(deltaX) < Math.abs(deltaY) * 1.15) return;
  if (deltaX < 0) {
    mobileRailManualOverride = true;
    setMobileRailHidden(true);
  } else {
    mobileRailManualOverride = false;
    setMobileRailHidden(false);
  }
}

document.addEventListener(
  'touchstart',
  (event) => {
    const touch = event.touches?.[0];
    if (touch) startMobileRailGesture(touch.clientX, touch.clientY, event.target);
  },
  { passive: true },
);

document.addEventListener(
  'touchend',
  (event) => {
    const touch = event.changedTouches?.[0];
    if (touch) finishMobileRailGesture(touch.clientX, touch.clientY);
  },
  { passive: true },
);

document.addEventListener('pointerdown', (event) => {
  if (event.pointerType && event.pointerType !== 'touch' && event.pointerType !== 'pen') return;
  startMobileRailGesture(event.clientX, event.clientY, event.target);
});

document.addEventListener('pointerup', (event) => {
  if (event.pointerType && event.pointerType !== 'touch' && event.pointerType !== 'pen') return;
  finishMobileRailGesture(event.clientX, event.clientY);
});

updateMobileRailMode();
compactHeaderMedia.addEventListener?.('change', updateMobileRailMode);

const certificateTrack = document.querySelector('[data-cert-track]');
const certificateSlides = Array.from(document.querySelectorAll('.certificate-slide'));
const certificateDots = Array.from(document.querySelectorAll('[data-cert-dots] span'));
const certificatePrev = document.querySelector('[data-cert-prev]');
const certificateNext = document.querySelector('[data-cert-next]');
let certificateIndex = 0;

function updateCertificateCarousel(nextIndex) {
  if (!certificateTrack || certificateSlides.length === 0) return;
  certificateIndex = (nextIndex + certificateSlides.length) % certificateSlides.length;
  certificateTrack.style.transform = `translateX(-${certificateIndex * 100}%)`;
  certificateSlides.forEach((slide, index) => {
    slide.classList.toggle('is-active', index === certificateIndex);
  });
  certificateDots.forEach((dot, index) => {
    dot.classList.toggle('is-active', index === certificateIndex);
  });
}

certificatePrev?.addEventListener('click', () => updateCertificateCarousel(certificateIndex - 1));
certificateNext?.addEventListener('click', () => updateCertificateCarousel(certificateIndex + 1));
